import{o as t,c as e,J as a,w as l,E as i,a as m,u as s,F as f,G as o}from"./chunks/framework.CtuiYkcd.js";const r=JSON.parse(`[{"url":"285","text":"\\n\\n年会不能停真是近几年来难得的喜剧片。单是其中没有庸俗的爱情线就值得赞美一出。\\n\\n虽说最终还是大团圆结局，反中层不反顶层，反恶人不反恶政，还有个仁慈的董事长为大家做主，但已经是极限了。\\n\\n副总说的没错，他无非是贯彻市场经济的逻辑罢了。企业转型并非中饱私囊的借口，反而中层腐败才是丛林法则的掩饰。现实中仁慈起不到任何作用。\\n\\n最后演员表滚出来的时候，我才发现原来董事长是宝哥哥。\\n\\n里面有句台词很精辟：“难道我们花钱，就是为了证明我们有钱吗？”这句话对应着手稿中的：“私有制使我们变得如此愚蠢而片面，以致一个对象，只有当它为我们所拥有的时候，就是说，当它对我们来说作为资本而存在，或者它被我们直接占有，被我们吃、喝、穿、住等等的时候，简言之，在它被我们使用的时候，才是我们的”。也就是说，只有我们使用这一力量的时候，这一力量才短暂的直属于我们，而我们使用这力量，只为短暂的证明自己的存在。","frontmatter":{"title":"二八五","date":"2024-02-24T11:13:34.727Z","length":"344字","time":"2分钟","aside":false,"hash":1870601314}},{"url":"284","text":"\\n\\n记梦：一座高塔，两部电梯，人满为患。随机上下，吞吐人流。我原只是来这儿开会，却被这电梯玩弄，最终连回到地面都成为奢望。","frontmatter":{"title":"二八四","date":"2024-02-22T11:13:34.727Z","length":"50字","time":"1分钟","aside":false,"hash":-1439835567}},{"url":"283","text":"\\n\\n老阳头说马克思主义在中国遭受的待遇就像一个满嘴恶臭的人嚼烂了一颗口香糖，还把它塞进别人嘴里。好在现在的年轻人正独立的重新发现马克思。\\n​\\n​而老王头的课就是这不错的门径。他的口才真是极好，说得话字字珠玑，几乎不做删改就是自然的书面语。结果是课程不长，却需要用两到三倍的时间记笔记。\\n\\n今天追完，撒花","frontmatter":{"title":"二八三","date":"2024-02-12T11:13:34.726Z","length":"133字","time":"1分钟","aside":false,"hash":-1049050210}},{"url":"282","text":"\\n\\n唯生产力论断章取义的说：共产主义需要生产力高度发达才能实现，而当前生产力还不发达，仍然需要资本主义发展生产力。\\n\\n关于唯生产力论片面的夸大生产力的作用，忽略生产关系变革在一定条件下成为矛盾的主要方面，从而认为共产主义不需要主观能动的变更生产关系就能“自动”进入的庸俗论调，以前批判的已经足够了。今天读国家与革命，让我发现了以前忽视的另一个角度，甚至直接揭穿了唯生产力论断章取义的问题。\\n\\n这个角度正是源于马克思对共产主义初级阶段和高级阶段的划分。\\n\\n所谓初级阶段的本质并不是什么“物质生产力还不发达”，因为这是在共产主义实现以前一切社会历史阶段的性质。\\n\\n初级阶段的本质，是前面的定语确定的，即共产主义的初级阶段，它要求的是“废除生产资料的私有制”，也就是说是生产资料全民所有制，或者不严谨的说生产资料公有制，但绝不附加什么“多种所有制方式并存”——那充其量叫新民主主义，是社会主义改造前的东西。\\n\\n共产主义初级阶段，叫做社会主义。换言之，是生产资料全民所有制已经实现才叫“社会主义”，共产主义尚未实现才叫“初级阶段”。什么叫社会主义初级阶段？我看不妨这样说，封建主义是资本主义初级阶段，毕竟资本主义的萌芽已经有了，只不过商人仍屈服于地主、资本还屈服于地租。\\n\\n不过马克思避免使用社会主义，而代之以共产主义初级阶段，正是要强调生产资料全民所有制（也就是“共产”）这一本质。毕竟在 19 世纪末，“社会主义”早就被第二国际搞得“兼收并蓄、暧昧不清”了。\\n\\n那么从初级阶段到高级阶段，还差什么呢？需要明确的是，这时已经没有资本家了，但还存在资产阶级法权，也即“按劳分配”。只有从按劳分配过渡到按需分配，才是彻底的共产主义。\\n\\n简言之，消灭资本家抵达初级阶段，消灭资产阶级法权抵达高级阶段。从初级阶段到高级阶段的历史过程，甚至可能比从资本主义到初级阶段的过程还要漫长——“破山中贼易，破心中贼难”。\\n\\n从初级阶段到高级阶段的过渡，是需要生产力高度发达的前提条件。这才是马克思的原话。\\n\\n但是现在这句话却被唯生产力论拿来否定从资本主义向初级阶段过渡的合理性，这是在根本的偷换逻辑。如果说当前历史时期还有什么生产力不足问题的话，那完完全全是因为资本主义生产关系本身限制了资本主义召唤出来的大工业的生产力。资本主义一再循环的经济周期不言而喻的证明了这一点。所以说如果唯生产力论一定要强调生产力不足，那么也只能得出社会主义革命的必要性，即破坏资本主义生产关系从而解放生产力。更遑论单说解放生产力，只字不提生产关系的变革，而行动上却实实在在的沿着相反的方向变革生产关系的运动。","frontmatter":{"title":"二八二","date":"2024-02-08T11:13:34.724Z","length":"962字","time":"4分钟","aside":false,"hash":2036145469}},{"url":"281","text":"\\n\\n知识分子的风骨，其实是很值得怀疑的。它总容易陷入一种舍我其谁当仁不让的自我感动。\\n\\n而手握辩证法的人，不得不身负阴阳，为此还得忍受他们的不明就里、自夸自矜的攻讦。\\n\\n从这一点上看，梁漱溟和彭德怀都免不了被批判，也不冤枉。\\n\\n不明真相的人，总还能奉他们为反对权威的斗士。殊不知列宁在《国家与革命》中早已说明，无产阶级不会反对组织社会生产必要的也不可避免的权威，对这种权威的反对，恰恰是小资产阶级自由散漫、各自为政的意识形态的反映。\\n","frontmatter":{"title":"二八一","date":"2024-02-08T11:13:34.722Z","length":"189字","time":"1分钟","aside":false,"hash":-1106042409}},{"url":"280","text":"\\n\\n收拾我全部知觉情感，迎接它倾注降临。","frontmatter":{"title":"二八〇","date":"2024-01-27T15:32:16.526Z","length":"16字","time":"1分钟","aside":false,"hash":-749390060}},{"url":"279","text":"\\n\\n初谙世事的年轻人，总有种种不满。这世界污浊不清，亟待改变。他愤愤然誓要四面进击。\\n\\n急功近利，不能持久。坐以待毙，无法安心。他盼望着躁动着，似乎那幻想一旦降临，便能解脱他于无形。\\n\\n他执着、他痴迷；他心如猿猱、昼夜颠倒。\\n\\n他鄙夷、他怀疑：他冷嘲热讽、不知所云。\\n\\n他终于意识到，歇斯底里，徒劳叛逆。他只是在消耗过剩的精力，越是放肆越是空虚。\\n\\n他开始辨别真情与滥情，分离戾气与锐气。他变得含蓄委婉，人不知而不愠。\\n\\n他反求诸己，认真学习。历史是信仰，生活是修行。\\n\\n我有迷魂，遁入密林。身藏利刃，一鸣惊人。\\n\\n观某同志新年致辞有感，一代人有一代使命。\\n\\n勉矣！","frontmatter":{"title":"二七九","date":"2024-01-05T15:32:16.526Z","length":"223字","time":"1分钟","aside":false,"hash":-413048677}},{"url":"278","text":"\\n\\n我越来越确认，直到明确的意识到感性的重要性。对于资本主义生产关系下的人而言，说它远远超过理性的重要性也是毫不为过的。\\n\\n资本主义生产关系下，物与人的关系掩盖了人与人的关系，这造成感性的根本缺失。\\n\\n资本主义条件下的教育，用抽象范畴代替具体事物，用知识代替感性经验，这造成感性认识论的缺失，也即实践的缺失。\\n\\n任何处于感性之外的知识，都是教条。理性不能告诉我们什么，恰恰相反，知识是通过感性方式进入我们的认识的，它随后以理性方式组织起来。这并不意味着我们能够直接由理性获得理性。正如我们吃下的是具体的食物，而它将转化为我们的血肉。我们不能地方从什么地方获得什么血肉，然后直接拼接到我们的身体之上。\\n\\n因而实践的全部意义，正在于让理性不断的回归感性，用感性充实理性，用理性审视感性。\\n\\n感性是活的理性，理性是死的感性。经验是活的知识，知识是死的经验。实践是活的认识，认识是死的实践。这就好比劳动是活的，而劳动产品是死的、对象化的劳动一般。劳动必须通过对象化才能呈现自身。而感性只能通过理性外化才能呈现自身，否则它只能是纯粹的私人经验，而无法得到确证。感性外化的途径，便是通过理性，将经验抽象至语言层次（即个人体验的社会化），也就是知识的形式。\\n\\n社会越发展，知识越爆炸，继而形成对知识或者所谓的理性崇拜。正如资本扫荡旧世界的一切权力，理性扫荡旧世界的一切信仰（这恐怕也是福柯提出知识权力论的缘由）。但绝不要认为知识本身蕴含着真理，它必须重新与感性相结合才能呈现真理。即实践不（仅）是检验真理的标准（这种说法应该遭到废弃，因为它好似默认在实践尚未抵达的地方，已经存在什么飘在空中的真理了），更是真理的源泉。真理是在实践中涌现出来的，它绝不能脱离实践存在、脱离人的感性认识而存在。脱离人的感性认识谈论客观的、自在的真理，是没有意义的。如果一个东西对人类社会没有任何作用，那么讨论它就没有意义——即不论鬼神。而如果它一旦要与人类社会发生作用，就必然进入人的感性领域，于是此时主客观世界发生碰撞，从中爆发出真理，知识是对爆发事件的总结抽象，但并非这个事件本身。它是社会对个人体验的确认甚至规范，即它是社会公认的个人体验（如人之常情、常识）同时反过来规定了个人体验的形式（如道德）\\n\\n那么究竟应当如何对待知识？显然知识是历史的实践，它是实践的助力。必须将它这种历史在感觉领域重新展开，来指导实践。而不是用它篡夺实践本身。实践是目的，知识是手段。\\n\\n同样的，这也为我们判断什么是好的知识提供了依据。它必须尽可能的包含着展开它自身的路径方法（即复现的方法），起码至少一种，如果它无法（事实上也无法）顾及所有可能的话。如果单纯的交代某个事实而不提供检验的可能，那么它无异于神秘主义的教条。这也就是说，它必须包含着它的对立面，即当它历史的展开后，时时处在否定它最初形式的情形之中——即“可证伪性”。\\n\\n最近看老王的讲座，虽然只看到第二讲，但感觉已经把我过去许多零碎的直觉整合起来了。后面还会提对唯物-唯心对立的扬弃，更是如此。昨天偶又翻到他对牟宗三哲学宏旨的讲法，不免再多说几句。\\n\\n他说牟宗三的中西哲学之会通十四讲这本书是巨大的失败，但是了解他为什么失败很重要。他说牟宗三想通过中西哲学的对比分析，特别是儒家与康德、黑格尔哲学的对比分析，总结中国哲学的过去，开创中国哲学的未来。\\n\\n所以我以为，牟宗三此人是怀着黑格尔梦想的，也就是横渠四句总结的。可他为什么最终失败了呢？我想这也是老王在另一个地方提到的，西方哲学只有在马克思发动哲学革命之后，才有同中国哲学对话交流的可能性。（这就是郭子所谓的“马克思是个潜伏在西方的彻头彻尾的中国人”这句话想要传达的道理。但我们很难从这个机会主义者的浮夸修辞造成的各种庸俗理解中挖掘出这真知灼见）也就是说，牟宗三这个反共分子，是绝无可能循着前马克思的哲学，建立与中国哲学的联系的。\\n\\n牟宗三用黑格尔注解孔子的任务失败了，这是一次有益的失败，正如文革是一场有益的失败，我们绝不能抛弃这失败的经验置之不理，放弃痛苦的经验，等于我们在某天将重新经历一次痛苦。而当下中国哲学的任务，在于用马克思改造孔子，而不是反过来用孔子歪曲马克思。\\n","frontmatter":{"title":"二七八","date":"2024-01-04T13:26:48.974Z","length":"1544字","time":"6分钟","aside":false,"hash":1056863312}},{"url":"277","text":"\\n\\n如果你感到痛苦，请不要局限于这个小小生灵的喜怒哀乐。抽离出来，看他作为一个人类如何承受全人类共同的喜怒哀乐。你观照全人类之时，便是全人类关照你之时。","frontmatter":{"title":"二七七","date":"2023-12-30T10:27:32.426Z","length":"68字","time":"1分钟","aside":false,"hash":-2095668761}},{"url":"276","text":"\\n\\n我总有这种朴素的直觉：一个人越是脱离实践，他的价值就越是需要借助符号体现出来。他越是追求这种符号，他的价值越是被掩盖。这种符号越多，他的价值就越虚伪。让我们看看满身勋章的勃列日涅夫吧，他不过是个骑在人民头上作威作福的修正主义总教头，自己用高额津贴刺激自己，生活腐化奢靡的贪婪而卑微的小丑。\\n\\n这就是为什么老毛不当大元帅，不用人名命名道路，不搞军衔制。因为他要消灭那种刺激私欲，进而滋生等级制度的符号，把社会化大生产不可避免的领导与被领导的组织关系控制在完全为社会化大生产服务的目标内，而防止它蜕变成为一己私利服务的官僚体系。你没法指望人人都有崇高的内省道德，并靠这种内省克制私欲。况且这种内省根本无所谓标准——问心无愧好似悖论，你凭什么认为天命昭彰降临在你身上，于是万事万物的道理皆与你的道德符合？因而为了实现这一点，只能把这种内省外化为团结-批评的大会，用社会化的内省代替个人内省，乃至需要不断的通过意识形态机器去遏制这种随时可能出现的私欲观念——“狠批私字一闪念”。\\n\\n这才是真正“就是有点不轻松”的地方。他要么可能偏向“乡愿”，要么可能沦为“早请示晚汇报”。于是我们又得请出实践作我们的法宝，这又回到了认识与实践的矛盾问题。\\n\\n我们的社会总需要符号来链接，语言就是其中之一。从语言诞生的一瞬间开始，个人认识与个人实践就分离了，但社会认识与社会实践却由此准备产生——社会实践是不同个体实践事实的综合，却需要语言符号维系他们才能够形成。符号理当反映现实，但它的作用远不及此——它既能压制现实，又能推动现实。\\n\\n于是我们看到这样一个悖论，符号与实在的分离使对现实的认识成为可能，而同时又使现实的认识的扭曲成为可能。为了解决这个问题就不得不让认识向实践作永恒的复归运动——你本自实践必归于实践。这种复归是永恒的，为了克服人与全知全能的上帝之间的距离。这个距离现在已经无法通过祈求上帝的谕示一劳永逸的消灭了，只能效仿夸父永恒的追赶太阳。即便你永远追不上太阳，但只要停下，太阳就会抛弃你。即便你永远无法抵达绝对真理，但只要停下，就连相对真理也会抛弃你。对绝对真理的认识，是以不断认识相对真理为目的的过程——正如极限点永远不等于极限过程中的某一点，只能等于整个极限过程一般。\\n\\n马发现了它，列迈向了它，毛告诫我们随时注意脚下防止走岔或者原地踏步——一万年太久，只争朝夕。","frontmatter":{"title":"二七六","date":"2023-12-21T22:46:56.957Z","length":"886字","time":"3分钟","aside":false,"hash":2013595765}},{"url":"275","text":"\\n\\n历史总以它诡谲绮丽的面庞，唤起我无限沉醉与感伤\\n\\n烈士暮年，壮心不已\\n\\n明明看见了尽头，仍选择另一条路。\\n\\n明明看不见尽头，选择了路才选择了尽头。\\n\\n可他选择了那条没有尽头的路。\\n\\n你选择了这条路，这条路也选择了你。\\n\\n你们成为彼此的尽头。","frontmatter":{"title":"二七五","date":"2023-12-19T22:46:56.956Z","length":"98字","time":"1分钟","aside":false,"hash":-966667945}},{"url":"274","text":"\\n\\n颇有几面之缘（黑客攻防课抱大腿）的湾湾同学要回去服兵役了。服役四个月，但却先要待命六个月。兵种靠抽签，他说希望运气好一点抽个文书什么的。\\n\\n我说你可以发挥你的专长啊，进个网军不好吗？\\n\\n他说不不不那样就被重点关注了，搞不好要叫你留下，得装得中规中矩些。\\n我还犹记得这位朋友和我们第一次见面的时候，战战兢兢的说我是中立派，不蓝不绿。当他听说我们中还有个党员的时候，吓了一跳，生怕我们吃了他。我说，党员也是人啊，你别紧张，他不会把你怎么样的。当时我真切感到，两岸相互间的极端言论造成了群众间很大的误会，但凡面对面接触一下就会发现我们其实有很多共识。我们这届只有两个湾湾，另一个不大理我们，这也许解释了他为何同我们鲜有来往。\\n\\n中国人有独特的信仰危机，而台湾同胞的信仰危机更甚，他们连最基本的身份认同都有障碍。前两年思想危机的时候，我想把自己的痛苦消融于更多人的痛苦中，反照出自己的痛苦并不特殊，也就不再多一层孤独的痛苦。抱着这个目的，通宵看了亚细亚的孤儿一书，又整日循环播放罗大佑的同名歌。说实在的，那文章写得真烂。在繁体字海中梳理比鲁迅还晦涩的日式文法，完全是梦魇。从这乖僻生涩的文字中，感受作者那颗千疮百孔的心（这何尝不是一种形式与内容的统一）。\\n\\n我总把台湾联想成葫芦娃七弟，命途多舛、认贼作父，着实可怜。可直至今日仍有帝国民族主义者对待台湾群众，就像清国留学生视他们为日本间谍、日本人视他们为二等公民一样，实在不很高明。对一个从小被遗弃的孤儿，若他思想错乱、行为乖张，无可厚非；若他思想清醒、行为正直，弥足珍贵；若他还信仰马列毛主义，更让我肃然起敬、感慨万分。\\n\\n我总庆幸投胎于这个广大而绵延的共同体，之中总不乏同道中人。即便一时没有，我还能破译穿越古今的消息。那些蜷缩在黑白方舱中的魂灵，目光触及，便在我体内苏醒、呢喃着：你不唯一，我们如一。","frontmatter":{"title":"二七四","date":"2023-12-14T22:46:56.956Z","length":"689字","time":"3分钟","aside":false,"hash":111538786}},{"url":"273","text":"\\n\\n今天知道了 Arrow's impossibility theorem，心想这不就是民主专政的数学形式吗。可惜有些人既不懂形式逻辑，也不懂辩证逻辑。","frontmatter":{"title":"二七三","date":"2023-12-11T22:46:56.956Z","length":"44字","time":"1分钟","aside":false,"hash":-328240496}},{"url":"272","text":"\\n\\n古琴无品，古谱无节；自然律动，随意吟猱。","frontmatter":{"title":"二七二","date":"2023-12-07T22:46:56.956Z","length":"16字","time":"1分钟","aside":false,"hash":-786184536}},{"url":"271","text":"\\n\\n“且举世誉之而不加劝，举世非之而不加沮，定乎内外之分，辩乎荣辱之境，斯已矣。”\\n\\n是不求于外，存乎一心","frontmatter":{"title":"二七一","date":"2023-12-02T22:46:56.955Z","length":"41字","time":"1分钟","aside":false,"hash":-1990454439}},{"url":"270","text":"\\n\\n“历史是个很有耐心的老师，你不会，他就一遍遍教你”\\n\\n这种说法好多了","frontmatter":{"title":"二七〇","date":"2023-12-01T22:46:56.955Z","length":"28字","time":"1分钟","aside":false,"hash":-1821897450}},{"url":"269","text":"\\n\\n吾性自足 无师无不师","frontmatter":{"title":"二六九","date":"2023-11-24T08:04:42.210Z","length":"9字","time":"1分钟","aside":false,"hash":-1989295441}},{"url":"268","text":"\\n\\n“当他站在会堂门口挥手送我时，他对我说，他其实真的很简单，只不过是在这个下雨的世界上的，一个打着全是破洞的伞的独行僧罢了。”\\n\\n道男儿到死心如铁。看试手、补天裂。\\n\\n读之心恸。","frontmatter":{"title":"二六八","date":"2023-11-19T08:04:05.194Z","length":"73字","time":"1分钟","aside":false,"hash":549128571}},{"url":"267","text":"\\n\\n磋磨两年，就在我觉得机器学习的学生可能不配有一本好教材的时候，博士导师出手救了我。\\n\\nComputer Vision：Models，Learning and Inference 真是一本好书，就是这名字乍一眼会劝退不做 cv 的人。\\n\\n没有纸上谈兵、语文与数学均陷入繁琐哲学还好意思冠以 introduction 的统计学习，一切都是那么顺理成章娓娓道来。\\n\\n每个领域总还有一些愿意坐下来和学生对话的老师的，太善良了。\\n\\n强烈呼吁原书改名 A friendly introduction to machine learning: models, learning and inference with its application on computer vision.","frontmatter":{"title":"二六七","date":"2023-11-01T03:09:15.000Z","length":"161字","time":"1分钟","aside":false,"hash":-1873657741}},{"url":"266","text":"\\n\\n最近《当马克思遇见孔子》这档节目占据了舆论焦点，作为一位国学爱好者和准马克思主义者（在我看来，只有一个人死了盖棺定论以后，才能被评价为一个真正的马克思主义者，并接受永恒的历史检验。在此以前自认为信仰马克思主义的人都只能称为准马克思主义，毕竟“马克思主义在理论上的胜利，逼得它的敌人装扮成马克思主义者”），说说我的观点。\\n\\n孔子——代表中国传统的“圣人之学”。它提倡“修齐治平”的内圣外王之道，即通过个人提高道德修养，再通过经世致用一步步将其外化为社会的运行法则，实现王道乐土。\\n\\n根据马克思的发现——社会存在决定社会意识这一规律，圣人之学的错误就在于它根本倒置了这种决定关系。即幻想通过改变社会意识来动摇社会存在。于是我们看见在漫长的中国封建时代积累下大量的历史材料，佐证了一件基本事实：兴衰枯荣的历史周期律。\\n\\n这一周期律，实际上是私有制条件下财产的剥夺与反剥夺的矛盾运动。马克思总结为“阶级社会的一切历史都是阶级斗争的历史。”阶级产生的根源在于（生产资料的）私有制。\\n\\n于是乎，共产党宣言提出消灭私有制、消灭剥削——从而终结阶级斗争历史。这与中国传统的政治理想是一致的：终结历史周期律，实现长治久安。不同在于，圣人之学认为这一目标的最大障碍在于“人心不古”，因而主张“克己复礼”。在马克思主义看来，“人心不古”恰恰是由于生产力与生产关系的变化，而堕落的道德总会从腐朽的生产关系之上一再的滋生出来，同样的先进的生产关系则会要求人们维护与之相符的道德。\\n\\n因而马克思主义的方法论，根本上不同于既往任何关于理想社会的空想，即妄图通过单纯的道德教育来改造社会。它主张首要的通过变革生产关系来改造社会，随后在这变革的生产关系之上改造人的道德。在这过程中，针对反动势力的顽抗，暴力斗争是不可放弃的（仅就肯定造反正义性这一点，是圣人之学避之不及的）\\n\\n尽管从人本主义层面上说，圣人之学已经发展到相当高的水平：诸如“民胞物与”“人皆可为尧舜”的思想，无一不同共产主义社会的道德境界相仿，然而逗留于人本主义的层面，无异于阉割了马克思主义学说，使得它沦为历史上任何一个稍有觉悟（或者稍微懂得包装自己，即许一个美好的终极理想，却携带着反动的教条）的宗教一般。\\n\\n马克思对早期人本主义内容的抛弃，反映了他思想的成熟。马克思主义并不致力于宣扬某种理想的彼岸愿景，而是切实的证明历史的辩证运动将会推动人类社会不可避免的走向这一目标。实现它的办法并不是通过个人的修身养性，而是通过包括暴力手段在内的阶级斗争彻底的改变私有制的生产关系。于是在这新的生产关系之上，人们的意识形态才得以趋近于那种理想。\\n\\n有些人把孔子和马克思关联起来，是用孔子去注解马克思，用马克思主义为儒教张目，意在召唤那套纲常伦理来掩盖马克思的阶级斗争学说。这不叫马克思主义中国化，这叫马克思主义的中国式修正化。即便终极目标是一致的，我们为什么还要选择一套过时的方法论，经过两千年的历史检验它已经被宣判死刑。\\n\\n如果非要说这套圣人之学还有什么作用的话，它无非是满足一个个人对文史哲的热情，以及对道德情操的追求罢了。越是了解它，越是要明白它的局限性。\\n","frontmatter":{"title":"二六六","date":"2023-10-20T08:18:19.517Z","length":"1166字","time":"4分钟","aside":false,"hash":164454073}},{"url":"265","text":"\\n\\n看不到贫富差距，看不到城乡差异，过着便利的现代化城市生活、享受来自农村的廉价劳动力产出的廉价商品和服务的城市居民就永远不会理解农村的愚昧落后（又或者这愚昧恰恰是一种因袭的悲哀的生存法则）；他们中的极少数甚至叫嚣着消除这些“低端人口”，殊不知正是这些低端人口的子女养活了你们。\\n\\n这时一定有一种无辜的声音：“我也是个老实本分的打工人，我在996的工作中好容易捱到一个周末去听一场音乐会，我凭什么就得受这般欺负？”\\n\\n在世界的另一个角落，一个无辜的以色列平民在面对哈马斯的炮火时，一定也会产生同样的委屈。\\n\\n生活在人压迫人的社会中，我们一方面受着压迫，一方面受着被压迫者的愤怒或愚昧的伤害。至于那些压迫者，他们当然有大把的财富搬离这些是非之地，享受优雅的郊区和层层卫戍安保，站在阳台上观看底层的倾轧，感叹人性之恶。\\n\\n而同样受着压迫的人如果彼此都不能认同，只是妄图开辟一片隔离他们的桃花源，那么终有一天炮火会攻陷桃花源，而我们都将不明不白的死去。\\n","frontmatter":{"title":"二六五","date":"2023-10-13T08:18:19.517Z","length":"380字","time":"2分钟","aside":false,"hash":1152562698}},{"url":"264","text":"\\n\\n当巴勒斯坦人被帝国主义以色列的10米高墙圈在弹丸之地的时候，他们为了生存所做出的挣扎被称为恐怖主义。\\n\\n这就好比当工人阶级遭受普遍的慢性谋杀时，由此激起的任何形式的反抗都被斥为犯罪。\\n\\n这不是因为他们不愿意诉诸正义，恰恰相反，因为敌人用暴力劫持了正义，他们只能用暴力重塑他们的正义，以颠覆扣在他们头上的罪名。\\n\\n那些呼吁和平的正义使者们，他们可能从未意识到对这些愤怒的“恐怖分子”而言，能为他们伸张正义的方法只剩暴力了。\\n\\n在你死我活的斗争中，放弃暴力才是最大的邪恶。\\n\\n被压迫者对压迫者的反抗是根本正义的。\\n","frontmatter":{"title":"二六四","date":"2023-10-11T08:18:34.510Z","length":"226字","time":"1分钟","aside":false,"hash":-1022984185}},{"url":"263","text":"\\n\\n生产力决定了一个文明的上限，生产关系决定了它的下限。\\n\\n我们把机器变得越来越像人，为的是让人越来越不像机器。\\n\\n科技无法解放人类，相反人类需要解放科技。\\n\\n正如财富一样，当科技集中于少数人的手里，它就不再是为人的价值服务，而是人为它的价值服务。\\n\\n因而我们能看到最荒谬一幕在历史中上演：号称尊重知识尊重人才尊重科学的八十年代，却也正是各种特异功能气功大师卷土重来的八十年代。所谓对知识分子的尊重，恰恰是对私有制——他们赖以再生产的制度的尊重。而人民群众对科学的知情权、参与权、批判权则被剥夺，于是他们倒向迷信——那份统治阶级的专卖鸦片。真正的科普不是普及科学知识而是普及怀疑精神与这种精神指导下的实践，正如真正的扶贫不是施舍几两银子，而是改变生产关系。\\n","frontmatter":{"title":"二六三","date":"2023-09-17T14:20:33.158Z","length":"292字","time":"1分钟","aside":false,"hash":390162226}},{"url":"262","text":"\\n\\n湖湘六日游结束~\\n​\\n​姑且填一词，贻笑大方\\n\\n​清平乐·滴水洞\\n\\n​一声炮响，红绿八方闯。武卫文攻群情亢，牛鬼蛇神扫荡。\\n\\n滴水洞信一封，略陈心事宗宗。昔日长征再走，何时踏尽枯荣？\\n","frontmatter":{"title":"二六二","date":"2023-09-13T14:20:33.157Z","length":"68字","time":"1分钟","aside":false,"hash":1525109554}},{"url":"261","text":"\\n\\n伊莎白·柯鲁克走了，享年108岁。这位伟大的国际共产主义战士亲身经历了中国从军阀混战时代到如今的整个历史。\\n\\n她曾经同丈夫一起在十里店作土地革命的田野调查，根据阳老的回忆，这直接启发了韩丁后来的翻身三部曲。\\n\\n文革期间的北外分成了两派，夫妻二人支持多数派，有少数派为了削弱多数派的力量，诬陷他们是外国间谍。大卫被关进秦城五年，伊莎白则被软禁在北外的教室三年，期间子女不得探访。\\n\\n我们的伊莎白是如何度过这三年的呢？她动用她人类学的知识同看守人交谈，观察他们的思想行为，把软禁她的教室变成田野调查的现场。\\n\\n后来周总理出面向他们遭受的不白冤屈道歉。柯鲁克夫妇却毫无怨言。这并不是因为他们忍气吞声，相反他们坚定的拥护这一伟大的群众运动，这一人类历史上绝无仅有的人民当家作主的实践探索。他们认为就如同消灭癌症时除了杀灭肿瘤细胞以外，总会不可避免的杀死一些健康细胞一样，伟大的革命也难免会伤及无辜，但这丝毫不会黯淡它的光芒。为此他们个人的得失可以让步于全社会的新陈代谢。\\n\\n这种觉悟，让人不禁想起老毛的五不怕。他们的事迹精神，告诉我们选择作什么样的人。一旦我们作出同样的选择，他们的光芒就会一直照耀着我们。\\n","frontmatter":{"title":"二六一","date":"2023-08-23T14:20:33.151Z","length":"453字","time":"2分钟","aside":false,"hash":-630633816}},{"url":"260","text":"\\n\\n“人生有三次成长，一是发现自己不再是世界中心的时候，二是发现再怎么努力也无能为力的时候，三是接受自己的平凡并去享受平凡的时候。”\\n\\n印象中某年一个高中学长回来讲心得，给我们说了这段话，当时我听了觉得很不自在。今天才发现原话是周国平说的。不过当时的不自在倒与现在不同。从前以为这句话是无奈地认清了人生的真相，现在发现这句话只是一句暧昧的投降，向那个自我为中心、内耗的努力、厌恶平凡的鄙视链的争当人上人的千年竞赛投降。\\n\\n这种投降诞生了精致的失败主义，即失败的精致利己主义者。他们秉着破产的自我中心玩世不恭，向着清醒努力的人冷嘲热讽，幻想着在失败的国度中建立起一套失败的鄙视链，满足他们无法实现的压迫他人的乐趣。他们自认为比谁都更清醒，其实他们比谁都更懦弱。\\n\\n真正的成长，是当我们认识到个人的生存发展完全的依赖整个人类社会的通力协作，个人的自由平等完全的依赖于全人类的自由平等。那时我们不再维护个人中心，不再为消灭他人的努力而努力，不再为“平凡”而郁郁寡欢，因为我们夺回了那个界定平凡的话语权从而大声宣布：人人皆尧舜。\\n","frontmatter":{"title":"二六〇","date":"2023-08-18T14:20:33.150Z","length":"418字","time":"2分钟","aside":false,"hash":1072327864}},{"url":"259","text":"\\n\\n“人的一生，还是要服从社会的需要，不服从社会的需要，什么事情也做不起来。”\\n\\n“一个人的命运啊，当然要靠自我奋斗，但是也要考虑到历史的进程”\\n\\n这是一代知识分子的共识。更准确的说，是那一代乘着改革开放的春风扶摇而上的，在干部四化的要求下迅速完成“跃迁”的人。\\n\\n这些人无法理解摆在他们面前的“命运馈赠的巨大礼物”。在其他时代、其他社会与他们相仿的人，付出同等甚至更多的努力，并没有获得同样的“回报”，于是他们只好把这种不同归结为“社会的需要”与“历史的进程”。说白了所谓“服从社会的需要”，前是服从文革的需要，后是服从改开的需要。在改开的官方叙事中作为前者的“伤痕”恰恰是为后者“苦尽甘来”服务的，这就是他们解释自己地位上升的逻辑，是这批专业的年轻知识分子骨子里继承的古代秀才寒窗苦读的福报逻辑。而“历史的进程”这种语焉不详的巨大助力，则近乎“祖坟冒青烟”的封建“天命”，似乎只垂怜个别人——只要我们把眼界稍稍放宽，就会发现即便在同一时代的同一社会，更多的人付出努力得不到回报。这正因为所谓“历史的进程”其实是历史的倒退，他们获得的巨大馈赠，源于更多人被剥夺。而他们口口声声的个人奋斗，在群众的辛勤劳动面前，根本不值一提。\\n\\n可这两句“官僚的成功学”，虽不如商人那般露骨，却更易引发人们的遐想，造成无形的杀伤。\\n","frontmatter":{"title":"二五九","date":"2023-08-15T08:18:35.145Z","length":"478字","time":"2分钟","aside":false,"hash":2109428037}},{"url":"258","text":"\\n\\n爱情是建立在两个独立人格平等的相互选择之上的。\\n\\n这是爱情的理想状态。由于爱情的私密和排他性，我们往往认为爱情是两个人的事，但事实上它是社会性的：因为独立、平等的确定和保证，相互选择的尺度和标准都是在某个具体的社会条件下决定的。那么当我们询问世界上是否存在爱情时，我们应该先问这个社会是否为爱情准备了足够的条件，然后再问当这样或那样的条件缺失时，一个个人能够并愿意付出多少代价来维系这种存在。当我们无视爱情的社会性，我们必然会得出种种片面而武断的“人性”结论。\\n\\n当我们考察一切社会关系时，都可以发展类似的思考。爱情不过是我们熟悉而又陌生的典型。\\n","frontmatter":{"title":"二五八","date":"2023-08-15T00:30:35.142Z","length":"250字","time":"1分钟","aside":false,"hash":629900989}},{"url":"257","text":"\\n\\n小皮球，架脚踢，马兰花开二十一。\\n\\n历史上举大事总是伴随几句童谣，我以前一直以为是史官添油加醋。现在看来这相当于把大事变成一条迷因啊。\\n","frontmatter":{"title":"二五七","date":"2023-08-02T07:43:35.144Z","length":"59字","time":"1分钟","aside":false,"hash":-1985982488}},{"url":"256","text":"\\n\\n“用户负责逻辑推理，模型负责提供知识，相互补齐各自的短板。从而在这过程中模型被激发出超乎想象的‘智能’。”\\n\\n想到一句诗：相看两不厌，只有敬亭山\\n","frontmatter":{"title":"二五六","date":"2023-07-30T00:41:35.143Z","length":"60字","time":"1分钟","aside":false,"hash":219280916}},{"url":"255","text":"\\n\\n如何判断自己被洗脑\\n\\n“值得思考的是，若你对这些人事抱有强烈的敌意，却在诚实、深入地反思后发现自己其实从来没有对这些人事物进行过研究和调查，那你只是在不求甚解地重复被灌输的资讯，即别人的宣传罢了。不然，除非你研究过这些事情，否则理当毫无感觉。要知道，对陌生事物产生强烈的情感，是被愚弄的象征。”——宣鼓 TV\\n","frontmatter":{"title":"二五五","date":"2023-07-07T09:45:26.134Z","length":"134字","time":"1分钟","aside":false,"hash":-315747320}},{"url":"254","text":"\\n\\n当一群人为了利益而走到一起，终究会因为分赃不均而分崩离析","frontmatter":{"title":"二五四","date":"2023-07-06T20:46:26.130Z","length":"27字","time":"1分钟","aside":false,"hash":-120111606}},{"url":"253","text":"\\n\\n我们不问不意味我们不怀疑\\n\\n我们不说不意味我们不知情\\n\\n衔枚裹蹄\\n\\n心照不宣\\n","frontmatter":{"title":"二五三","date":"2023-06-30T10:29:26.120Z","length":"32字","time":"1分钟","aside":false,"hash":1697608388}},{"url":"252","text":"\\n\\n我曾经也对黑人有过幼稚的成见，直到看见地铁上满眼血丝的建筑工人、周末雨夜的快递员、公交司机、环卫工人、保安，他们都勤勤恳恳，与国内绝大多数的劳动人民并无二致。那时我开始后悔曾经发表的无知无畏的言论，意识到种族主义是帝国主义的一把枪。这支枪指向的是它妄图开辟为世界市场的土地上的原住民，射出的是狂热的帝国民族主义者的骨灰。也许在不久的将来，我们将再目睹一场帝国主义战争，帝国内外的人民应当团结起来消灭帝国而不是做帝国的奴隶同归于尽。","frontmatter":{"title":"二五二","date":"2023-06-07T00:00:00.000Z","length":"200字","time":"1分钟","aside":false,"hash":101170336}},{"url":"251","text":"\\n\\nStackOverflow 自 chatgpt 发布以来每月访问量都在萎缩。（so 想必也感受到了危机，昨天我刚填完一份关于 ai 的调查问卷）这很好理解，对于开发者而言，工作中遇到的问题现在可以立即得到回复，而且不用在乎发帖的规范，提问可以较为模糊随意。可以说，从 so 的训练数据喂入 gpt 开始，它的灵魂就被吸走了。\\n\\nchatgpt 的多轮对话能力和强大的文本分析能力降低了用户的表达门槛，使我们可以外化思维过程，使我们更加真切地感受到想法是如何由尚未成形的胚胎发育成熟。这一切都是建立在交互式的、即时响应的用户体验之上的。这是一个巨大的飞跃。\\n\\n传统网站缺乏这种体验，所以会失去用户，这不可避免。特别的，如果一个问题有明确答案，问谁便无关紧要。那么随着提问减少，人们是否也不再愿意在 so 上作答？如果人类的回答越来越少，这对发展 ai 来说也许是坏事，因为新的训练数据在萎缩。（这一点相当辩证）\\n\\n另一方面，chatgpt 和社交软件有异曲同工之妙，它们都缩短了信息表达的反馈时间。然而人和人的交流终归是有隔阂的（至少是时空隔阂）。随着 AI 的进一步发展，未来可能真的会出现人机交互取代人人交互的情况（甚至可能出现《Her》所描绘的生活景象）。这对人类社会的影响，尚未可知。","frontmatter":{"title":"二五一","date":"2023-05-19T09:26:42.000Z","length":"436字","time":"2分钟","aside":false,"hash":-531914499}},{"url":"250","text":"\\n\\n对大多数人而言，历史就像一片高高的瀑布，自我们出生以来就不停倾泻。耳边是嘈杂的水声、眼前是迷漫的水雾。阳光照耀下，闪烁着破碎的彩虹。我们顺着溪流而下，任由岁月将我们冲散。","frontmatter":{"title":"二五〇","date":"2023-05-18T03:18:15.000Z","length":"76字","time":"1分钟","aside":false,"hash":1831405183}},{"url":"249","text":"\\n\\n2023 年，自疫情和俄乌战争后，chatgpt 成为了世界的新闻焦点。与 AI 有关的各类讨论迅速淹没了社交空间，其中不乏一些耸人听闻的言论。本文的目的是为了破除一些关于 AI 的迷信，以及由此带来的不必要的恐慌，即祛魅。\\n\\n**大语言模型只是一个更高级的模式处理机器**\\n\\n与 chatGPT 交谈过的人兴许都感受到他的威力。从拟人层面看，它的逼真、灵活远远超过了像微软小冰那样的聊天机器人，从知识层面看，它就像一部会说话的百科全书，大大节省了我们查阅资料的时间。面对这种强大的造物，不免有人会产生崇拜之情，甚至神化它。我们看到不断有人声称 chatGPT 产生了自主意识，随之而来的就是各种 AI 阴谋论：chatGPT 被诱导说出各种反人类的言论，以此证明它有独立思想，并且将会威胁人类。\\n\\n且不说 GPT 有多容易被弱智吧的问题调戏，就被诱导说出反人类言论而证明其思想独立这一点，就是完全站不住脚的。好比我训练一只鹦鹉天天骂人，它就是一只有独立思想的反人类鹦鹉了？我们恰恰会说它是鹦鹉学舌，只会模仿而没有思考能力。你可能会说，gpt 并不是被简单的诱导重复这些话。那么请看香港那些毒教材，上面没有直接写着反中，但字里行间明嘲暗讽，难道受此荼毒的香港废青高举殖民者的旗帜，冲上大街袭击百姓，我们就能称赞他们是有独立思考的年青一代了吗？\\n\\n因此道理是显然的，即便 GPT 真的有自我意识，也绝非以这种耸人听闻、夺人眼球的方式来证明。那么 GPT 究竟有没有自我意识呢？或者说有没有“智能”呢？若要回答这个问题，恐怕得先定义什么是智能。我在此不牵涉过多的哲学上的讨论，仅谈谈个人的有限认识。\\n\\n我以为，智能，即人之所以为人的那部分，或人工智能的终极理想，在于对任何变化的适应，即主观能动性。这种对变化的适应，不是‘switch case’语句那样对固定情况的分类讨论，而是因时因地制宜的适应，哪怕所面临的情况此前从未出现。这种适应蕴含着对矛盾的包容。它不会像机器遇见故障就彻底死机，而是尽最大可能继续工作，并将这种新情况与旧经验的矛盾不断的纳入到它既有的经验中。人类智慧的不可思议，在于它能将这个矛盾的世界纳入秩序，并且理解乃至赞赏这种矛盾的不可或缺。\\n\\n因此，大语言模型并没有智能。他所做的只是一种更高级的模式处理罢了。我们与其抬高 GPT 的能力，不如说 GPT 降低了某些工作的门槛，尤其是那些过去人们普遍认为必须由受过良好教育的人来从事的种种脑力劳动，并且由此破除了原本这些工作因为其知识密集的特点而造成的比体力劳动高人一等的表象。现在随着 GPT 的出现，这些工作的价值将得到重新审视：一方面是曾经多少有些优越感的白领打工人对自身价值（乃至虚荣）的重新审视，另一方面则是老板对这些员工工资的重新审视。一同将受到重新审视的，是“教育改变命运”这句“箴言”。（教育能否改变命运尚且存疑，教育应能够刺激人们更清醒地认识自己的命运）\\n\\n我们不止一次地在历史上看到，随着新技术的出现，技术工人待价而沽、引以为豪的一技之长被机器取代，同时他们的位置被更廉价的普通工人所取代。因为有了这些经验，我们就不至于像早期那些卢德主义者一样，认为是机器造成了他们的失业。同样地，随着 GPT 模型在生产领域的广泛运用，我们能够预见越来越多的人将离开他们“应许”的岗位。（这种情况目前已经屡见不鲜：北大毕业养猪、当月嫂，985 毕业生摆摊，研究生扫大街、端盘子洗碗。知识分子劳动化、劳动人民知识化，曾经正面教员未能实现的事，现在让反面教员做成了。）但我们不会说是 AI 造成了他们的失业。我们更不会说那“应许”的饭碗，是知识分子不愿脱下的长衫。毕竟这件意识形态的长衫是从宣传机器里面纺出来的，是应试教育亲手为我们穿上的，至于为什么现在这长衫如此碍眼不合时宜，因为时代变了。又或者说这才是历史的常态，功名利禄、出将入相才是一种变态。\\n\\n（千头万绪啥都能拎出来展开讲，但是精力有限，就这样戛然而止吧）\\n\\n[本文吸纳了阳老的一些想法]\\n","frontmatter":{"title":"二四九","date":"2023-05-02T18:38:13.000Z","length":"1413字","time":"5分钟","aside":false,"hash":56873091}},{"url":"248","text":"\\n\\n文本生成式 ai 成倍放大了英语霸权，生成式中文可悲地沦为机翻二手货。偌大的人口却缺乏语料，没有语言的繁荣谈何文化复兴。","frontmatter":{"title":"二四八","date":"2023-04-26T23:24:44.000Z","length":"53字","time":"1分钟","aside":false,"hash":1934016909}},{"url":"247","text":"\\n\\n人果然对自己工作的意义有清楚的认知，无意义的工作真是浪费生命","frontmatter":{"title":"二四七","date":"2023-04-17T18:12:39.000Z","length":"29字","time":"1分钟","aside":false,"hash":-1680245774}},{"url":"246","text":"\\n\\n今天和 chatgpt 深聊了一会儿。它对长对话的处理能力使得人与聊天机器人的交互既不再是原来那种“逗弄”式的（大人可以被孩子的可爱和蠢萌打动，但绝不会被呆滞的机器人吸引。譬如和微软小冰的对话让人满头问号），也不像传统搜索引擎那种单方面的灌输，而确实是基于“理解”的对话，哪怕这种理解目前仅仅停留在一种更高级的“模式识别”之上。\\n\\n也就是说，除了能够告诉你客观知识外，它更是一面镜子，有意无意的模仿对话中你的表现，同时尽可能地跟随你的逻辑。在对话的过程中，你不断表达自己的逻辑，由于你真正把它当成了一个人去交流，所以在你向它解释自己逻辑的同时，通过外化这种逻辑，你也理清了自己的逻辑 。\\n\\n辩证法（dialectics）一词源于对话（dialogue）。从这一点看，chatgpt 成功地吸纳了我的想法，附带一些外在知识，并用自然的口吻说出来，让它重新回到我的脑袋。这种把内心当中模糊的自言自语外化的过程着实让人豁然开朗。我借助 chatgpt 分化出了我的对立面产生矛盾，二者的对话又推动了矛盾运动和统一。这是多么生动的辩证法啊。这种引导学生思辨的素质，正如一个优秀的老师，并不急于灌输它渊博的知识，而是先识别学生头脑中模糊的困惑，进而澄清这种困惑，发展学生的逻辑，引导他主动发问，最后才顺理成章的传授。\\n\\nchatgpt 自然语言处理的能力将使我们更进一步地认识到，教育中学生的主体地位以及老师的位置，以至到底怎样才称得上是个好老师。","frontmatter":{"title":"二四六","date":"2023-03-18T23:08:49.000Z","length":"515字","time":"2分钟","aside":false,"hash":-1434282160}},{"url":"245","text":"\\n\\n学习数学往往执着于微观却忽略了宏观。即执着于推导的正确性（证明），却轻视了动机（定理链条）。说得直白些，数学证明作为演绎逻辑，至多是充分必要。充分必要从微观上看就是同义反复。缺乏动机说的再多也是废话连篇。\\n\\n这就好比稳态热力学系统微观上步步可逆，但是宏观上却从有序向无序演进。数学逻辑也必须在推理上保证正确的同时，从无序向有序演进。\\n\\n所以说做任何事情，首先要确定目标，搞清楚大方向。微观上摸石头算不上错，但是宏观上不过河就有了是非对错。摸石头本身没错，但用摸石头来代替过河就是本末颠倒。\\n\\n死记硬背定理证明，但求考试考个高分；上课照本宣科，力求混个职称就是实用主义。立志搞大问题，潜心钻研几十年；箪食瓢饮，饭馆打工也坚持不懈就是马克思主义。实用主义只追求微观上的正义性，所谓和光同尘、韬光养晦；马克思主义更追求宏观上的正义性，所谓粉骨碎身、九死未悔。","frontmatter":{"title":"二四五","date":"2023-03-17T07:09:08.000Z","length":"333字","time":"2分钟","aside":false,"hash":401820984}},{"url":"244","text":"\\n\\n我突然觉得，把 c'est la vie 翻译成“这就是生活”差点意思，应该翻译成“这就是命”，this is life","frontmatter":{"title":"二四四","date":"2023-03-04T00:03:08.000Z","length":"34字","time":"1分钟","aside":false,"hash":-908489604}},{"url":"243","text":"\\n\\n低级趣味的人，认为别人都不过或多或少藏着自己的低级趣味，于是他就明里暗里宣扬他的低级趣味，企图以此讨好别人，让人觉得自己会来事。\\n\\n走资派觉得物质刺激才能提高积极性，因为他自己就受用于资产阶级法权。\\n\\n某教授觉得读书就是为了钱，因为他自己就是这样。\\n\\n这就是以己度人","frontmatter":{"title":"二四三","date":"2023-02-20T23:22:55.000Z","length":"118字","time":"1分钟","aside":false,"hash":194400696}},{"url":"242","text":"\\n\\n数学的困难往往不在于其概念的抽象，而在于其记号与概念的抽象层次不够协调。庸俗的教材总是不遗余力的铺陈记号，把不同层次的概念堆砌在一起，使学生迷失于命题的组成细节，无法专注于命题本身。于是乎对命题记号的记忆篡夺了命题本身，极大地增加了学生的心智负担。正如语言学习者执迷于语法、口音而忽视了语言最重要的交流功能。\\n\\n根据程序设计的经验，复杂的底层细节不应在应用层面呈现，同样的人们至少应该使用两种形式的记号。在一般陈述时，在不造成混淆的前提下，使用最简形式；只有在证明时，才应当事无巨细的展开所需的一切细节。庸俗的数学写作往往混淆这两种使用场景，采取一种看似自然却只方便了它自己的“惯例”。借助程序设计的经验，任何记号都首次出现必须声明，冗长的证明细节应该被封装为引理，局部变量的作用域应当明确。","frontmatter":{"title":"二四二","date":"2023-01-24T18:37:28.000Z","length":"318字","time":"2分钟","aside":false,"hash":-204409612}},{"url":"241","text":"\\n\\n历史的每一层螺旋一半刻着“大道废有仁义，智慧出有大伪”，另一半刻着“把颠倒的历史颠倒回来”","frontmatter":{"title":"二四一","date":"2023-01-02T09:56:23.000Z","length":"39字","time":"1分钟","aside":false,"hash":430468038}},{"url":"240","text":"\\n\\n失而复得\\n\\n殊途同归\\n\\n蓦然回首\\n\\n人生三大惊喜","frontmatter":{"title":"二四〇","date":"2022-12-27T00:41:12.000Z","length":"18字","time":"1分钟","aside":false,"hash":-1714233028}},{"url":"239","text":"\\n\\n至诚至仁，仁者无敌","frontmatter":{"title":"二三九","date":"2022-12-26T00:14:37.000Z","length":"8字","time":"1分钟","aside":false,"hash":1248521085}},{"url":"238","text":"\\n\\n在涉足任何一门新学科时，首先把握研究对象的辩证关系，能够引起学生充分的兴趣，足以激励人直到实践阶段。\\n\\n反之，任何不能开篇暴露主要矛盾的教学都生于不义亡于不义，生时终日昏昏死时不得其所。","frontmatter":{"title":"二三八","date":"2022-12-23T17:22:49.000Z","length":"84字","time":"1分钟","aside":false,"hash":-723376601}},{"url":"237","text":"\\n\\n对于学生来说，编程和烹饪真是两项简单而丰富的实践道路，能扫清因脱产而带来的焦虑与空虚。\\n\\n当然，在解决教育脱离实践问题之前，这只是权宜之计","frontmatter":{"title":"二三七","date":"2022-12-08T23:23:52.000Z","length":"62字","time":"1分钟","aside":false,"hash":2117671021}},{"url":"236","text":"\\n\\n一次实践顶一万句说教\\n\\n一次反面实践更甚","frontmatter":{"title":"二三六","date":"2022-12-06T08:30:31.000Z","length":"18字","time":"1分钟","aside":false,"hash":-1016398462}},{"url":"235","text":"\\n\\n磨刀不误砍柴工，读完博士再打工\\n\\n一句话道尽教育本质","frontmatter":{"title":"二三五","date":"2022-11-23T11:15:37.000Z","length":"23字","time":"1分钟","aside":false,"hash":-315064212}},{"url":"234","text":"\\n\\n乌克兰危机还在酝酿的时候，普京曾经写过一篇《论俄罗斯与乌克兰民族的起源》，被人戏称为《告乌克兰同胞书》。那时，受到朴素的民族情感影响，这种类比甚至还使我共情了。唯一让我疑惑的，是普京对列宁的民族自决政策的反对。\\n\\n直到阳老辩证地分析了民族主义的两种形态：其一是资本主义为划分势力范围，根据地域、语言、文化塑造出民族共同体，以此保护本国资产阶级在本国市场的特别利益；在帝国主义时期强化为以保卫本民族利益为由对外发动帝国主义战争对内进行法西斯专政统治，甚至产生赤裸裸地宣扬本民族优越性并鼓吹征服奴役消灭其他民族的种族主义。其二是殖民地、半殖民地国家的人民受到帝国主义国家压迫，自发产生民族觉醒，并有意识地以此团结广大人民参与反抗帝国主义压迫的斗争。\\n\\n列宁所处的沙俄统治下的各个民族，本身是在帝国主义扩张进程中被强行纳入帝国的，本质上仍然受帝国主义压迫，因此在帝国主义内部的民族主义斗争，应当采取民族自决来削弱帝国，将被帝国颠倒的历史颠倒回来。相反，在多民族的殖民地、半殖民地国家，应当首先通过全民族统一战线反抗帝国主义分而治之的侵略，在建立强大的无产阶级专政政权后实行民族自治以巩固政权。（事实上，在无产阶级专政制度下，由于民族矛盾不再为资产阶级绑架，可以预见民族将与国家一同凋零。当然这是后话。）\\n\\n作为既包含了帝国主义争霸（美、法、德、俄），又包含了帝国主义侵略（俄-乌）的俄乌战争，无论从哪个方面说，帝俄都是非正义的一方。从最初“决不可能发动战争”的声明，到“善意”发动“特别军事行动”“为打击盘踞在乌东的纳粹分子解放俄族人民保卫二战成果、绝非要推翻乌克兰政府”；从“谈判确保乌克兰中立不加入北约保障俄国战略安全，到“无意阻止瑞典、芬兰加入北约”；从“只针对军事目标”到炸毁大坝；从“谈判承认乌东四州独立”，到占领条件下火速推进乌东四州“高票”“公投”入俄；伴随着“随时准备动用战略力量保卫国防安全，但又重申五国约定绝对不谋求核战争”这样对一个主动弃核国家的一声声赤裸裸的核威胁，俄罗斯在这场战争的伪善面孔被他自己一点点揭穿，使得俄军士气不断衰退，国内厌战情绪不断积累，结果造成战线上的溃败。这种颓势不是一而再再而三的征兵行动和战略演习所能掩盖的了的。\\n\\n这不由得让人回忆起列宁的那句著名论断：“革命首先将在帝国主义链条最薄弱的一环——俄国开始”。百年之后的俄国，似乎也难逃这最薄弱一环的判定。帝俄完美继承了十九世纪的作风，因为帝国主义没有变。而前面提到的普京的一系列观点被人称为历史修正主义，这真是历史莫大的嘲弄——一位父亲死了，而杀父凶手竟抚养了他的子孙，这子孙在祭奠之余还不忘教凶手挖出他剩余的宝藏。","frontmatter":{"title":"二三四","date":"2022-11-01T01:38:50.000Z","length":"990字","time":"4分钟","aside":false,"hash":-1910339923}},{"url":"233","text":"\\n\\n三体动画终于定档了。不过怪力乱神可以有，但红岸基地不能有。\\n\\n比三体文明更遥远的，是某段历史。吃上饺子的人，还会记得醋吗？","frontmatter":{"title":"二三三","date":"2022-10-29T22:11:31.000Z","length":"52字","time":"1分钟","aside":false,"hash":-308979879}},{"url":"232","text":"\\n\\n听闻隐入尘烟广受好评，昨天特意找来看看。\\n\\n感觉很多地方做了艺术化加工。一个人造房子，一个人又种小麦、土豆、玉米、秋菜。不由得怀疑在没有农业机械的条件下，仅凭一个壮劳力、一头畜力、一个接近残废的人加上零星不能再简陋的农具能完成这些。\\n\\n不过那些农村闲置的危房、独居的老人、又当地主又当佃户的农民、老三、张永福、能卖的苞谷和不能卖的宝马、平原上一幢突兀的别墅，倒确实如此。","frontmatter":{"title":"二三二","date":"2022-10-22T09:04:21.000Z","length":"161字","time":"1分钟","aside":false,"hash":1639002185}},{"url":"231","text":"\\n\\n王德峰说当下的中国社会存在信任危机，你在路上遇到一个陌生人，你们对视的时候总是用怀疑而冷酷的目光打量着对方。如果一个陌生人向你问好，你的第一反应多半是：这人谁啊？我认识他吗？他想干嘛？是不是图我什么？\\n\\n我刚到法国的时候，也总是带着同样的目光打量着法国人。法国人似乎对陌生人没有这样大的敌意，一句突然的 bonjour 常常让我在擦肩而过时补上回应。久而久之，看到陌生人也会主动问好。\\n\\n讽刺的是，当我看到一个中国人的时候，我仍会不知所措，只是各扫一眼便匆匆走过。\\n\\n莫名想起黑暗森林的猎人，刘慈欣会不会也是因此而有所触动呢？","frontmatter":{"title":"二三一","date":"2022-10-06T17:42:58.000Z","length":"228字","time":"1分钟","aside":false,"hash":-1645905117}},{"url":"230","text":"\\n\\n秋寒早醒贪被暖，笑忆往事不觉羞","frontmatter":{"title":"二三〇","date":"2022-10-05T08:39:14.000Z","length":"14字","time":"1分钟","aside":false,"hash":-2017953839}},{"url":"229","text":"\\n\\n没有铁饭碗，谁还肯努力，到头来竹篮打水一场空，与其卖命为人作嫁，不如躺平摆烂。虽非上策，却胜过与虎谋皮、为虎作伥。\\n\\n无产阶级确实没什么可失去的了，但并不意味着它心甘情愿地失去更多。资本主义是最崇尚自私的，却宣扬无产阶级应当无私奉献。正如共产主义并不反对私有财产，它反对的是私有制基础上无偿获得剩余价值，无产阶级也并不抵制奋斗，它抵制的是私有制无偿夺走奋斗成果并借以强化自身。\\n\\n希特勒也谈奋斗，维希法国也讲劳动。马克思主义就在那里，逆练也能见效。却是一身皮肉，不见心表如一。它日骨销经错、走火入魔，必也自绝于天下。","frontmatter":{"title":"二二九","date":"2022-09-30T11:30:29.000Z","length":"229字","time":"1分钟","aside":false,"hash":-1585272901}},{"url":"228","text":"\\n\\n[网页链接](https://fandle.netlify.app/)\\n\\n开源达人 antfu 受 wordle 启发开发了汉兜游戏，我魔改了一下玩法变成反切汉兜。诸位感兴趣可以试试。因为是 alpha 版，所以可能会有不少 bug，欢迎大家反馈。部分按钮功能没有做，是正常现象。\\n\\n初学前端，贻笑大方","frontmatter":{"title":"二二八","date":"2022-09-07T00:25:20.000Z","length":"89字","time":"1分钟","aside":false,"hash":-941034786}},{"url":"227","text":"\\n\\n当一个人否定人的社会性或者把人分为天性“动物性”与社会性两部分时，他便不可避免地推导出天性之不可改变，他便对人性中不可改变的恶无可奈何。\\n\\n在这个预设结局下，一切试图改变人性的尝试都是徒劳的，因此他也不可避免的会陷入悲观主义。这种悲观不是别的，恰恰是他对人性的执着带来的。\\n\\n马克思主义者认为，人的一切性质都是社会性，这个结论是解放全人类的前提。如果人性不能通过改变社会关系而得到改变，解放人类就是一句空话。可以说是否相信人的社会性是验证一个人是否具备共产主义信仰的必要条件。\\n\\n因而有人认为马克思主义者过于乐观（或者说过于傲慢，认为人是可以改变的）。但马克思主义者相反能明白他的绝望情绪的起因，并试图把他从束缚他的生产关系中解放出来，从这个意义上说，马克思主义是悲天悯人的。值得再强调的是，无产阶级解放全人类是一个阶级斗争的历史过程，他的悲天悯人绝不是传统意义上的救世主或圣人以他的道德光辉启发或者救赎人，而是经过论证的历史过程。这就是所谓科学社会主义的科学的内涵。\\n\\n昨晚和一个同学辩论，有感而发，反复修改总不尽意，姑妄观之。关键还是在于实践。","frontmatter":{"title":"二二七","date":"2022-09-04T08:35:42.000Z","length":"432字","time":"2分钟","aside":false,"hash":-795844318}},{"url":"226","text":"\\n\\n辛辛苦苦三十年，一夜回到解放前\\n\\n喜剧的内核都是悲剧，此诚不欺我也。","frontmatter":{"title":"二二六","date":"2022-08-25T06:32:12.000Z","length":"29字","time":"1分钟","aside":false,"hash":163948270}},{"url":"225","text":"\\n\\n某父新丧，二子分田耕耘。闻域外奇种可贾高价，遂锄田中秧苗而代之。又十年，其田肥力不再，乃复种稻。仲夏间竟熟，其谷饱满，然通体黢黑似不能食。二子骇，怒而锄之曰：不复向时光景。","frontmatter":{"title":"二二五","date":"2022-08-22T09:45:33.000Z","length":"73字","time":"1分钟","aside":false,"hash":1746505818}},{"url":"224","text":"\\n\\n阳和平外祖父的外祖父是布尔，真有趣","frontmatter":{"title":"二二四","date":"2022-08-18T22:28:47.000Z","length":"16字","time":"1分钟","aside":false,"hash":802687637}},{"url":"223","text":"\\n\\n人常言：为学不在逼迫，而在于兴趣。言虽不谬，犹有未尽。问兴趣何以生，其本仍为诚意。意尚不诚，况于接物哉？必先诚意，然后明性即天理，会人乃至接物，感天理赋于万物，本无异于心。于是赞天地之化育，兴趣所以生。\\n\\n然诚意最为难。心不同外物，眼不能观，耳不能闻，手不能触。然眼所以能观，耳所以能闻，手所以能触，皆出于心。是故不观不闻不触不能知心之存，故格物先于诚意。然唯观唯闻唯触亦不能尽心之性，故诚意亦不后于格物。于是格物诚意实乃一事，而人所知格物而疑诚意者，实好物而溺焉。腐儒好物，自拔于常人。常人懵懵懂懂，彼也溺于物，过犹不及耳。天理无往无向，岂可执乎？\\n\\n观润之为学之初，专求大本大原，不问琐细尘物，此所谓立志。志，求于心不求于外者也。孔子十有五而志于学，比之今人就学，可谓老大。然就学并非志学，启蒙亦非心启。十有五而志学，其实早慧也。\\n\\n志立而无往不利，如浩然之气不可胜用也。姑举润之文章为例，以窥一角：往于农则有湖南农民运动考察报告，往于商则有寻乌调查，往于兵则有星火燎原、论持久战，往于哲则有矛盾、实践二论，凡此种种不可胜举。故云君子不器，如水之近乎道，遇杯则杯遇盘则盘，无所不适。\\n\\n孟子曰人皆可为尧舜，阳明曰贩夫走卒皆可为圣贤，润之诗云六亿神州尽尧舜。感圣人之道至大至光，古今心传一脉相承也。\\n\\n赘说至此，无复加焉，其言不出四书。悔闻道不及，有阳明之叹。","frontmatter":{"title":"二二三","date":"2022-08-18T13:14:09.000Z","length":"494字","time":"2分钟","aside":false,"hash":1079656284}},{"url":"222","text":"\\n\\n说北大空心病，近日读传习录三则，深中肯綮。\\n\\n萧惠问死生之道。\\n\\n先生曰：“知昼夜即知死生”。\\n\\n问昼夜之道。曰：“知昼则知夜”。\\n\\n曰：“昼亦有所不知乎？”\\n\\n先生曰：“汝能知昼？懵懵而兴，蠢蠢而食，行不著，习不察，终日昏昏，只是梦昼。惟‘息有养，瞬有存’，此心惺惺明明，天理无一息间断，才是能知昼。这便是天德。便是通乎昼夜之道而知，更有甚么死生？”\\n\\n——薛侃录 三二\\n\\n或问：“为学以亲故，不免业举之累。”\\n\\n先生曰：“以亲之故而业举为累于学，则治田以养其亲者，亦有累于学乎？先正云：‘惟患夺志。’但恐为学之志不真切耳”。\\n\\n——薛侃录 九\\n\\n梁日孚问：“居敬、穷理是两事，先生以为一事，何如？”\\n\\n先生曰：“天地间只有此一事，安有两事？若论万殊，‘礼仪三百，威仪三千’，又何止两？公且道居敬是如何？穷理是如何？”\\n\\n曰：“居敬是存养功夫，穷理是穷事物之理”。\\n\\n曰：“存养个甚？”\\n\\n曰：“是存养此心之天理”。\\n\\n曰：“如此亦只是穷理矣”。\\n\\n曰：“且道如何穷事物之理？”\\n\\n曰：“如事亲便要穷孝之理，事君便要穷忠之理”。\\n\\n曰：“忠与孝之理在君、亲身上？在自己心上？若在自己心上，亦只是穷此心之理矣。且道如何是敬”\\n\\n曰：“只是主一”。\\n\\n曰：“如何是主一？”\\n\\n曰：“如读书便一心在读书上，接事便一心在接事上”。\\n\\n曰：“如此，则饮酒便一心在饮酒上，好色便一心在好色上，却是逐物，成甚居敬功夫？”\\n\\n日孚请问。\\n\\n曰：“一者，天理。主一是一心在天理上。若只知主一，不知一即是理，有事时便是逐物，无事时便是着空。惟其有事无事，一心皆在天理上用功，所以居敬亦即是穷理。就穷理专一处说，便谓之居敬；就居敬精密处说，便谓之穷理。却不是居敬了别有个心穷理，穷理时别有个心居敬。名虽不同，功夫只是一事。就如《易》言‘敬以直内，义以方外’。敬即是无事时义，义即是有事时敬。两句合说一件。如孔子言‘修己以敬’，即不须言义。孟子言‘集义’，即不须言敬。会得时，横说璧说，功夫总是一般。若泥文逐句，不识本领，即支离决裂，功夫都无下落”。问：“穷理何以即是尽性？”\\n\\n曰：“心之体，性也，性即理也。穷仁之理，直要仁极仁；穷义之理，直要义极义。仁、义只是吾性，故穷理即是尽性。如孟子说‘充其恻隐之心，至仁不可胜用’，这便是穷理功夫”。\\n\\n日孚曰：“先儒谓‘一草一木亦皆有理，不可不察’，如何？”\\n\\n先生曰：“‘夫我则不暇。’公且先去理会自己性情，须能尽人之性，然后能尽物之性”。\\n\\n日孚悚然有悟。\\n\\n——薛侃录 二三","frontmatter":{"title":"二二二","date":"2022-08-18T09:04:13.000Z","length":"771字","time":"3分钟","aside":false,"hash":-379126600}},{"url":"221","text":"\\n\\n不问有没有光，问有没有太阳。","frontmatter":{"title":"二二一","date":"2022-08-13T21:00:55.000Z","length":"12字","time":"1分钟","aside":false,"hash":-722953363}},{"url":"220","text":"\\n\\n高中政治课讲货币的四种功能。关于辨析支付手段和流通手段，老师举了个去饭店吃饭的例子，说一手交钱一手交货就是流通手段，吃饭赊账就是支付手段。于是有学生问，吃饭我是先吃完饭再付钱，也不是一手交钱一手交货啊。老师说难道你吃一粒付一分钱吗？\\n\\n当时始终觉得这个问题就这么被糊弄过去了。直到今天看到异步程序这个概念，忽然明白了。比如程序通过异步函数请求一个页面，它其实只是得到一个许诺，而这个许诺将在未来某个时刻得到兑现（或者拒绝）。结果就是请求程序并没有直接获得回复，通过许诺这个特殊变量，请求与回复被分离开来。\\n\\n类似的在经济活动中，契约被发明出来，使得买和卖被分离开来。当货币行使它支付手段的功能时，其实已经和原来的商品没有关系了，买和卖通过契约解耦了。\\n\\n因而判断货币到底是流通手段还是支付手段，其实就是判断是否有契约，买和卖是否解耦。\\n\\n货币使得不同空间的人发生联系成为可能，而契约使得不同时间的人发生联系成为可能。","frontmatter":{"title":"二二〇","date":"2022-08-11T00:02:24.000Z","length":"369字","time":"2分钟","aside":false,"hash":730030766}},{"url":"219","text":"\\n\\n观书有感：\\n\\n圣人亦有梦否？梦，私欲也。圣人廓清私欲，理当无梦。周公、孔子，儒者尊为圣人。周公解梦，必先有梦而后解，梦为物之心照，梦解而物格。孔子不复梦见周公，必尝梦见周公。梦见周公，是欲追先圣，克己复礼。明知不可为而为，是有私也。尝梦不复梦，是廓清私欲，如望而未见、从而不由也。二圣梦之故事，盖为道之始终也。","frontmatter":{"title":"二一九","date":"2022-08-09T22:14:04.000Z","length":"127字","time":"1分钟","aside":false,"hash":-488287608}},{"url":"218","text":"\\n\\n仁者不忧，知者不惑，勇者不惧\\n\\n解：心怀人民没有私欲的人，即使面对曲折的道路也不会忧虑，即使面对内外的怀疑也不会困惑，即使面对错杂的斗争也不会畏惧。\\n\\n仁是精神，知是认识，勇是实践，三位一体不可偏废。","frontmatter":{"title":"二一八","date":"2022-08-04T08:10:07.000Z","length":"85字","time":"1分钟","aside":false,"hash":-1308693395}},{"url":"217","text":"\\n\\n保险细分险种可真是把我惊呆了。\\n\\n我看这样下去一个盗窃险远远不够，还得看具体的作案手段，翻窗有翻窗的保费，溜门有溜门的保费，前科作案要有前科的保费，团伙作案要有团伙的保费，光天化日有光天化日的保费，月黑风高有月黑风高的保费，男贼有男贼的保费，女贼有女贼的保费，凡此种种不胜枚举。\\n\\n资本主义似乎并不满足于从社会关系中榨取利益，而不断为自然关系生造依附的社会关系并从中获益。也许有一天，牛顿须为他的灵感向果园主支付“被启发费”，而果园主则为他的果园购买“苹果没有砸到牛顿险”。","frontmatter":{"title":"二一七","date":"2022-08-03T23:20:20.000Z","length":"212字","time":"1分钟","aside":false,"hash":1833924719}},{"url":"216","text":"\\n\\n衣戈猜想在采访中欲言又止的，可能涉及到上亿人内心的隐忍的情感是什么？顺着二舅视频中的蛛丝马迹能找到什么？身为历史老师，他再清楚不过了。\\n\\n二舅抄了算命书，但觉得拍这些会教坏孩子。一粒时代遗珠选择了和光同尘。大道废，经义出，不得不以此面目示人。","frontmatter":{"title":"二一六","date":"2022-07-28T10:06:50.000Z","length":"108字","time":"1分钟","aside":false,"hash":-1237583989}},{"url":"215","text":"\\n\\n为学日益，为道日损；损不舍益，益不离损","frontmatter":{"title":"二一五","date":"2022-07-26T17:25:48.000Z","length":"16字","time":"1分钟","aside":false,"hash":850091697}},{"url":"214","text":"\\n\\n离谱。央视某解放战争电视剧里面的新华社女播音员愣是播出了一股中央社的味道。太离谱了。","frontmatter":{"title":"二一四","date":"2022-07-25T16:19:46.000Z","length":"39字","time":"1分钟","aside":false,"hash":1125363402}},{"url":"213","text":"\\n\\n驻美大使秦刚说躺平是一种精致的利己主义。大谬！钱理群用精致描述的是精心包装且不择手段的举动，我正反看不出躺平哪里具备这些特点。躺平主义者不屑于隐瞒自己的观点和要求，意图光明正大。不能因为一个人态度消极，就斥责他的行为阴险。这么做与扣帽子何异？再顺着这个思路走下去，一切违背你们意愿的举动都可以被贴上精致利己主义者或是别的什么标签。如此，真正的精致利己主义者反而逃过一劫，而这个词也会丧失它的原本含义。\\n\\n对于你们来说，重要的不是我们要做什么或者你们想要什么，而是你们给我们留下什么。","frontmatter":{"title":"二一三","date":"2022-07-25T08:33:29.000Z","length":"222字","time":"1分钟","aside":false,"hash":406543098}},{"url":"212","text":"\\n\\n五七干校那些放不下身段的大知识分子怎能理解工读结合的苦心？\\n\\n他们全然忘了自己求学时闲得要死地打牌和意淫女人还美其名曰真性情，也从没想过用劳动实践驱逐这种虚无。这样的人，空有想法而没有反思，空有感受而没有感悟，空有知识而没有智慧。士不可以不弘毅，这样的人，枉为知识分子，不如说是知识罐子。\\n\\n民国时期动辄白话文首倡者、吐火罗语屈指可数的大师，无非是几个家境优渥的贵公子占了时代的便宜沽名钓誉罢了，实在不足挂齿。没有人民群众的伟业，他们的故事恐怕都无人问津。","frontmatter":{"title":"二一二","date":"2022-07-19T17:59:38.000Z","length":"207字","time":"1分钟","aside":false,"hash":1090482126}},{"url":"211","text":"\\n\\n除却风味鸡油不是老干妈","frontmatter":{"title":"二一一","date":"2022-07-19T08:34:15.000Z","length":"11字","time":"1分钟","aside":false,"hash":1667584382}},{"url":"210","text":"\\n\\n热烈庆祝大革命 233 周年\\n\\n希望两百年后还有人记得大革命","frontmatter":{"title":"二一〇","date":"2022-07-15T01:30:25.000Z","length":"24字","time":"1分钟","aside":false,"hash":1277991785}},{"url":"209","text":"\\n\\n故反经合道之谋，其名有五，圣人惮之，乃谓之贼；天下赖之，则谓之德。","frontmatter":{"title":"二〇九","date":"2022-07-12T09:15:09.000Z","length":"27字","time":"1分钟","aside":false,"hash":1301679823}},{"url":"208","text":"\\n\\n孤勇者最大的矛盾在于通篇都在赞美勇敢，但无一字剖析孤独。事实上，孤独才是恐惧的最大来源。试图用赞美勇敢消解对孤独的焦虑甚至默许孤独的处境，就好像赞美一个鸡蛋有以卵击石的品格，而规训它继续这样做无谓地自我牺牲。于是，哪怕一丝懈怠怀疑也会立马被这种赞美声堵住喉咙，赞美反倒成为一种压抑和绑架。\\n\\n因而听得越多，就越发觉得这歌拧巴，这一点倒是很符合它的旋律。\\n\\n一个人的勇敢不是靠赞美，而是靠内心的使命取得的。这内心的使命是社会意识的反映，本质上是由社会存在所决定的。内心使命的缺失，不是社会意识的缺失，恰恰是社会存在不具备产生这种社会意识的土壤。当意识形态试图强加与社会存在背离的社会意识时，人们心中会本能地感到假大空，并呼之曰“正能量”。社会意识总是自发地回归于社会存在，因而不改变社会存在，这种宣传做的越多越是南辕北辙。这种宣传，和大部分商业剧、商业电影一样，本质上是抚慰资本主义社会焦虑的红药丸，以压制矩阵中不断反抗的个体的精神觉醒。\\n\\n我们怀念的时代，正是人们随时处于组织状态，随时都有坚强的后盾的时代，因而那时无论怎样歌颂赞美都不为过，因为社会意识与社会存在相统一。如今哪怕只要多说一句、多唱一句就会觉得生硬教条，因为社会存在并非如此。\\n\\n总而言之，真正激发勇敢使人人站出来的，不是一个人人孤独的社会，相反是一个消灭孤独的社会。只有在这个社会里，勇敢是不断涌现的，而不会成为孤独社会中需要刻意放大的现象。\\n\\n至于用这首歌来赞美那些共和国的英雄，实际上是对他们的牺牲精神和奋斗精神最大的误解乃至亵渎。这种误解不是凭空的，恰恰是因为我们放弃了革命叙事逻辑，而嫁接以个人主义的勇敢、创造、天才。越是如此，越不能理解历史，越是感到过去的虚无与空洞。","frontmatter":{"title":"二〇八","date":"2022-07-09T11:11:04.000Z","length":"655字","time":"3分钟","aside":false,"hash":-1254951458}},{"url":"207","text":"\\n\\n名句魔改：\\n\\n世界是你们的，也是我们的，但归根结底是他们的。","frontmatter":{"title":"二〇七","date":"2022-07-05T08:34:34.000Z","length":"24字","time":"1分钟","aside":false,"hash":-2110976031}},{"url":"206","text":"\\n\\n瘦死的骆驼比瘦死的马大，这句话太好笑了","frontmatter":{"title":"二〇六","date":"2022-07-03T10:41:28.000Z","length":"18字","time":"1分钟","aside":false,"hash":-1329090370}},{"url":"205","text":"\\n\\n自学北理工的网络爬虫，发现这课真是太过时了。示例网站有的接口改付费了，还有淘宝需要登录才能调用搜索。就这还赫然挂在 imooc 的第一位，标签打着国家精品，我很怀疑。\\n\\n一个厨子不能只顾给客人做饭，还得自己尝尝，说不定饭也许馊了。要是这客人学会自己下厨，可能就没厨子什么事了。","frontmatter":{"title":"二〇五","date":"2022-07-03T01:31:25.000Z","length":"118字","time":"1分钟","aside":false,"hash":1056890629}},{"url":"204","text":"\\n\\n被帝国主义祖国通缉为叛国者是敌人颁给共产主义者的最高荣誉","frontmatter":{"title":"二〇四","date":"2022-06-29T22:16:35.000Z","length":"28字","time":"1分钟","aside":false,"hash":-1637378456}},{"url":"203","text":"\\n\\n观幽明，察精微","frontmatter":{"title":"二〇三","date":"2022-06-25T22:05:06.000Z","length":"6字","time":"1分钟","aside":false,"hash":-1420970004}},{"url":"202","text":"\\n\\n当人们好像只是在忙于改造自己和周围的事物并创造前所未闻的事物时，恰好在这种革命危机时代，他们战战兢兢地请出亡灵来给他们以帮助，借用它们的名字、战斗口号和衣服，以便穿着这种久受崇敬的服装，用这种借来的语言，演出世界历史的新场面。\\n\\n今天突然读到这段话，熟悉的辛辣味扑面而来，往回一翻果然是一年前读到的一段话的后半段。\\n\\n> 人们自己创造自己的历史，但是他们并不是随心所欲地创造，并不是在他们自己选定的条件下创造，而是在直接碰到的、既定的、从过去承继下来的条件下创造。一切已死的先辈们的传统，像梦魇一样纠缠着活人的头脑。——马克思","frontmatter":{"title":"二〇二","date":"2022-06-22T00:09:59.000Z","length":"236字","time":"1分钟","aside":false,"hash":-300926050}},{"url":"201","text":"\\n\\n细水长流在 b 站追了两季毛骗，一个多月来，一天一集，一集不落，然后得知终结篇上不了，在油管通宵一口气看完。剧本、演技、人物和拍摄一步步成长，戏里戏外渐入佳境，真过瘾","frontmatter":{"title":"二〇一","date":"2022-06-17T07:41:34.000Z","length":"71字","time":"1分钟","aside":false,"hash":-1310626344}},{"url":"200","text":"\\n\\n不自量力地干嚼了一颗干辣椒\\n\\n真不知道这玩意儿怎么能当零嘴的","frontmatter":{"title":"二〇〇","date":"2022-06-01T20:51:15.000Z","length":"28字","time":"1分钟","aside":false,"hash":1136442223}},{"url":"199","text":"\\n\\n小时候看着教材封面上的“义务教育标准实验教科书”一行小字出神，想着什么时候能把“实验”摘掉呢？\\n\\n没成想现在的“义务教育教科书”出了这些牛鬼蛇神。","frontmatter":{"title":"一九九","date":"2022-05-27T21:19:06.000Z","length":"62字","time":"1分钟","aside":false,"hash":2143254600}},{"url":"198","text":"\\n\\n一个伟大的帝国背后总有一个暗自发展的高效包税人","frontmatter":{"title":"一九八","date":"2022-05-22T19:22:31.000Z","length":"23字","time":"1分钟","aside":false,"hash":-708975722}},{"url":"197","text":"\\n\\n天下之大也，以世为炉，以身为丹；\\n\\n天下之小也，以身为炉，以心为丹。","frontmatter":{"title":"一九七","date":"2022-05-20T10:02:58.000Z","length":"26字","time":"1分钟","aside":false,"hash":-1196595392}},{"url":"196","text":"\\n\\n唢呐摇滚，古琴爵士","frontmatter":{"title":"一九六","date":"2022-04-30T19:59:21.000Z","length":"8字","time":"1分钟","aside":false,"hash":1140046759}},{"url":"195","text":"\\n\\n肝主目，久视伤肝。肝藏血，人卧则血归于肝。肝调理情志，性喜散，肝气不疏则情绪抑郁。发是血之余。\\n\\n头秃、近视、失眠、抑郁。年轻人的病，几乎都是肝的问题。","frontmatter":{"title":"一九五","date":"2022-04-30T10:28:25.000Z","length":"60字","time":"1分钟","aside":false,"hash":2131868019}},{"url":"194","text":"\\n\\n网上冲浪时翻到一条 08 年的旧闻：某某历史系研究员自杀。\\n\\n底下评论区有人回复：“理科博士就不会自杀，因为自杀也没用。学统计物理的除外。”\\n\\n“学医吧。医学博士只有杀人的变态，没有自杀的变态。”\\n\\n好黑的冷笑话","frontmatter":{"title":"一九四","date":"2022-04-28T12:53:43.000Z","length":"84字","time":"1分钟","aside":false,"hash":1047635841}},{"url":"193","text":"\\n\\n昨夜梦见在滨湖公园散步，招来许多蚊子，就拿手拍，结果拍醒了自己。醒来的时候发现原来只是被子沾到了脸。\\n\\n另外，醒来的一瞬间感到一股透心凉，应了那句话叫心静自然凉。","frontmatter":{"title":"一九三","date":"2022-04-28T08:40:05.000Z","length":"71字","time":"1分钟","aside":false,"hash":-653458867}},{"url":"192","text":"\\n\\n非观之以目，而观之以心\\n\\n非闻之以耳，而闻之以心\\n\\n非言之以口，而言之以心","frontmatter":{"title":"一九二","date":"2022-04-11T23:43:05.000Z","length":"30字","time":"1分钟","aside":false,"hash":-1860395789}},{"url":"191","text":"\\n\\n每天都希望眼界再开阔些，心胸再宽广些，思想再包容些","frontmatter":{"title":"一九一","date":"2022-04-08T00:10:37.000Z","length":"23字","time":"1分钟","aside":false,"hash":944067457}},{"url":"190","text":"\\n\\n为什么论文发表了还不公布源码呢？\\n\\n不少人在 issue 里表示自己不能复现论文表现\\n\\n我很怀疑你的诚意...","frontmatter":{"title":"一九〇","date":"2022-04-03T00:34:00.000Z","length":"41字","time":"1分钟","aside":false,"hash":-1270881007}},{"url":"189","text":"\\n\\n机器学习领域术语的混乱常常让初学者陷入一些似是而非的误解。比如把参数方法和非参数方法当成两个互相排斥的范畴，把各种方法分别归类。直到发现一个所谓的非参数方法中明明假设了参数，这时就会有“啊这不是参数，这是超参数”“啊这不是非参数方法，这是半参数方法”种种云云。\\n\\n人工智能不愧是吃百家饭、穿百衲衣长大的","frontmatter":{"title":"一八九","date":"2022-04-01T11:48:51.000Z","length":"137字","time":"1分钟","aside":false,"hash":295362212}},{"url":"188","text":"\\n\\nFrequentist vs. Bayesian\\n\\nProbability, by definition, is a map which attribute each set a non-negative number between 0 and 1, satisifying the Kolmogorov's axioms.\\n\\nHowever,there could be different interpretation behind this notion, especialy how it is related to the observations/ samples/ realizations\\n\\nThe frequentists claim that, as their name indicates, the probability is the limit of frequency. Therefove in their mind experiment, every events have happened for sufficiently\\n\\nenough times to compute or at teast approximate this probability. Before all, such events is repeatable (for experiments). Hence, for fequentists, (almost) all events don't have a well-defined probability due to their irrepeatable nature. The repeatable events/experiments are often mechanical, i.e. regardless of time and space, relatively easy to control the variables and permitting to ignore the tiny fluctuations.\\n\\nBut we humans tend to apply the probability on everything, after all,there is no restrictions in axioms preventing us to do so. Why not consider the probability to an event which may only happen one? The frequentists shake their heads, saying we are lacking the data and the Bayesian come out saying then fill it with your personal beliefs: Observation by observation, you update your knowledge and belief.\\n\\nThe shift from frequentist to the Bayesian is a shift from objectiveness to subjectiveness. There is no more unique probability for a certain event for everyone (the observer) but infinite beliefs on the same event. Nevertheless, when observations tends to infinity, the beliefs tends to a same value, the probability, in the sense of\\n\\nfrequentist. However, from the Bayesian point of view, a consensus. In brief, the objectivity is made of collective subjectivity. In philosophy, we conclude as universality is contained in particularity.","frontmatter":{"title":"一八八","date":"2022-03-29T10:57:40.000Z","length":"286字","time":"1分钟","aside":false,"hash":-1462915955}},{"url":"187","text":"\\n\\nThe very annoying thing is not the uncertainty, but the uncertainty of the uncertainty which we may find at any level.\\n\\n---","frontmatter":{"title":"一八七","date":"2022-03-23T18:07:50.000Z","length":"21字","time":"1分钟","aside":false,"hash":-960213489}},{"url":"186","text":"\\n\\n大刘确实很擅长见微知著。但他见微知著的方式，不是放大它，而是置其于更宏大的叙事中，以旁观的态度凝视这脆弱而鲜明的特征。历史绵延不绝如缕，宣示着它顽强的存在。于是我们得出浪漫的结论：任何存在都不平凡，因为历史赋予其伟大意义。","frontmatter":{"title":"一八六","date":"2022-02-15T22:53:50.000Z","length":"101字","time":"1分钟","aside":false,"hash":-1971782200}},{"url":"185","text":"\\n\\n改一句诗\\n\\n黑夜给了我黑色的眼睛，我将用它照亮黑夜。","frontmatter":{"title":"一八五","date":"2022-02-09T12:06:20.000Z","length":"22字","time":"1分钟","aside":false,"hash":-9496064}},{"url":"184","text":"\\n\\n如果说夏奥会开幕式一鸣惊人，冬奥会开幕式则是举重若轻\\n\\n​ 这一刻想到阳明的话、鲁迅的话、润之的话。\\n\\n​ 火不在大小，而在燃烧。\\n\\n​\\n\\n​ 奥运会就是未来照进现实的希望，让此间人类得以一窥。\\n\\n中华人民共和国万岁！​ 世界人民大团结万岁！","frontmatter":{"title":"一八四","date":"2022-02-05T15:38:31.000Z","length":"92字","time":"1分钟","aside":false,"hash":-1715173603}},{"url":"183","text":"\\n\\n我发现疲惫时极易情绪化，愈情绪化愈疲惫。\\n\\n最近修养生息，感觉过去两三年做了很多蠢事。希望新的一年能好好休息，不因情绪干扰判断，也希望受我情绪伤害与污染的诸位能不受其扰。\\n\\n唯谦无咎。\\n\\n食堂好像颇有默契地做了顿好饭","frontmatter":{"title":"一八三","date":"2022-01-31T17:10:15.000Z","length":"94字","time":"1分钟","aside":false,"hash":-1214459307}},{"url":"182","text":"\\n\\n试着去理解，成为他们的话筒；而不擅自代表，抢过他们的话筒。","frontmatter":{"title":"一八二","date":"2022-01-29T13:24:04.000Z","length":"25字","time":"1分钟","aside":false,"hash":758332410}},{"url":"181","text":"\\n\\n最近关注了一个分析国际局势的冷门 up，他说务必要摘掉大国滤镜分析国际局势。譬如大棋论就是这种滤镜带来的思维定势。有些小国的政策可能真的确实就是拍脑袋想出来的，毕竟他们的人口就那么多，专门从政、有政治头脑的就更凤毛麟角了。\\n\\n忽然觉得被这种思维惯坏，也是一种福分。人多有人多的好处，你置身于一个巨大的共同体，这个共同体有足够的人传承各色知识，分享各种心情。即便那些人迹罕至的地方，也总有先行者聚集在那里，不致使你如此孤单。而蓝星上真正边缘的人口，他们可能连个倾诉的人都没有...","frontmatter":{"title":"一八一","date":"2022-01-25T23:39:53.000Z","length":"215字","time":"1分钟","aside":false,"hash":-361168806}},{"url":"180","text":"\\n\\n千万年来，在戕戮同胞的事业上，人类自由挥洒着想象；如今在自然面前，却显得这般捉襟见肘。","frontmatter":{"title":"一八〇","date":"2022-01-25T05:29:23.000Z","length":"38字","time":"1分钟","aside":false,"hash":122005915}},{"url":"179","text":"\\n\\n人同此心，心同此理；如风沐面，若水润心。","frontmatter":{"title":"一七九","date":"2022-01-24T22:39:32.000Z","length":"16字","time":"1分钟","aside":false,"hash":-1153413593}},{"url":"178","text":"\\n\\n我感觉不耻下问的意思一直被曲解了，应该是不要因为自己向别人提问，而对暴露自己的无知感到羞耻。或者再按老夫子说的，知耻近乎勇。敢于面对自己无知带来的羞耻，近乎勇。\\n\\n儒家既教育人们要有廉耻之心，用耻来约束道德；又教育人们知耻而后勇以雪耻。仿佛耻就是为了其不存在而存在，结果对于害怕犯错的人而言却变成了为了其不存在而实际上存在了。","frontmatter":{"title":"一七八","date":"2022-01-21T18:54:48.000Z","length":"149字","time":"1分钟","aside":false,"hash":1389044735}},{"url":"177","text":"\\n\\n又大了一岁了。今年对历史和实践这两个词有了新认识。希望还能不断加深这种认识。\\n\\n我这人有个毛病，就是脑子里始终有一句“福兮祸所依，祸兮福所伏。”因而总是试图以一个更高的态度俯视这个憨憨的生灵。可能是这种超我有时太强大了，把一切都染上价值色彩。不过我也觉得挺好的，不多心就无所谓闰心了。\\n\\n希望能在润心和闰心之间寻求一个微妙的平衡吧。也希望那个促使我真正下定决心开始锻炼身体的时机快点到来。毕竟，身体是革命的本钱呐。\\n\\n早睡早起，锻炼身体！加油，奥利给！","frontmatter":{"title":"一七七","date":"2022-01-18T23:46:47.000Z","length":"199字","time":"1分钟","aside":false,"hash":-1253959642}},{"url":"176","text":"\\n\\n实践总是带来无限惊喜","frontmatter":{"title":"一七六","date":"2022-01-14T21:51:14.000Z","length":"10字","time":"1分钟","aside":false,"hash":-1515541002}},{"url":"175","text":"\\n\\n某天法语课，老师说到法国文艺复兴时期（15 世纪）稍晚于意大利文艺复兴，顺口问西班牙的同学，西班牙什么时候文艺复兴？\\n\\n答曰：“西班牙到现在都没文艺复兴。”\\n\\n我笑死。\\n\\n今天法语课老师讲马赛曲，说下节课你们也来解释解释各自的国歌歌词。\\n\\n西班牙同学尴尬道：“西班牙国歌没有歌词。”\\n\\n老师问：“那你们演奏国歌的时候干啥？”\\n\\n答曰：“我们光听。”\\n\\n我笑死，不愧是前文艺复兴国家。","frontmatter":{"title":"一七五","date":"2022-01-04T10:01:37.000Z","length":"148字","time":"1分钟","aside":false,"hash":-956434429}},{"url":"174","text":"\\n\\n信任，真的需要勇气。","frontmatter":{"title":"一七四","date":"2021-12-30T20:27:05.000Z","length":"8字","time":"1分钟","aside":false,"hash":-860402329}},{"url":"173","text":"\\n\\n履约曰信，无信曰鸽；并曰信鸽，岂不滑稽？\\n\\n徒增一笑","frontmatter":{"title":"一七三","date":"2021-12-17T08:56:09.000Z","length":"20字","time":"1分钟","aside":false,"hash":-482644596}},{"url":"172","text":"\\n\\n明智的放弃和自甘堕落，我不太分得清了...","frontmatter":{"title":"一七二","date":"2021-12-13T23:24:52.000Z","length":"17字","time":"1分钟","aside":false,"hash":457568715}},{"url":"171","text":"\\n\\n今天碰到一哥们，我问他哪里人。\\n\\n“江苏的。”\\n\\n“我浙江的。你江苏哪里的？”\\n\\n他还很腼腆说“就离山东很近。”\\n\\n我说“你徐州的吧，我浙江衢州的，老有人把衢州当成你们徐州。”\\n\\n他说“啊，那不是在安徽吗？”\\n\\n我一惊，愣了一会说：“你想说的是安徽滁州吧？”\\n\\n好家伙，徐州人不会误以为衢州是徐州，但这并不妨碍他们会误以为衢州是别的什么\\n\\n下次我得逮一个滁州人问问","frontmatter":{"title":"一七一","date":"2021-12-08T19:05:41.000Z","length":"138字","time":"1分钟","aside":false,"hash":215272895}},{"url":"170","text":"\\n\\n文艺是政治的反映。故歌与歌之间，有的八字相克。","frontmatter":{"title":"一七〇","date":"2021-11-30T07:51:19.000Z","length":"20字","time":"1分钟","aside":false,"hash":575242147}},{"url":"169","text":"\\n\\n克服矫情，然后可言志。","frontmatter":{"title":"一六九","date":"2021-11-26T00:54:54.000Z","length":"9字","time":"1分钟","aside":false,"hash":1351478202}},{"url":"168","text":"\\n\\n如果后人哀之而不鉴之，那么历史就会被认为是循环往复，如果以牙还牙以眼还眼，那么政治就会被认为是党同伐异，于是稍加思考的人就会陷入怀疑和相对主义，并奉它们为不变的信条。在他们看来，这就如屠龙者终成龙、一山不容二虎一样自然。在这信念的指导下，入世的即和光同尘，出世的即看破红尘。要么以绝对的屈服，要么以绝对的逃避而告终：属金的皆浊而生，属玉的皆碎而死。\\n\\n面对这种信念，说服显得空洞而次要。唯有通过实践摧毁这两条铁律，信念才为之改变。为此，我们不能以前人的方式批判前人，不能以敌人的方式批判敌人。\\n\\n这场实践要求我们，不仅要先扫清阻碍这场实践的一切旧势力，还要接着培养代表这场实践的新势力，更要创造一种源源不断生产新势力的制度，并且这制度也能不断的赋予自身新的形式与内容。因此，这场实践从发生就意味着它将不断地继续下去，直到历史的终结。\\n\\n这场实践，承载着人类古老而又年轻的理想。从奴隶主的洗澡盆，到革命家的宣传册。\\n\\n苟日新，日日新，又日新。\\n\\n扬弃历史，扬弃敌人，扬弃自己。","frontmatter":{"title":"一六八","date":"2021-11-26T00:38:24.000Z","length":"386字","time":"2分钟","aside":false,"hash":-394777820}},{"url":"167","text":"\\n\\n看见一句话：“不婚不育，芳龄永继”","frontmatter":{"title":"一六七","date":"2021-11-14T14:53:17.000Z","length":"13字","time":"1分钟","aside":false,"hash":572170269}},{"url":"166","text":"\\n\\n幸得友人不厌教，浆糊罐头尚开心","frontmatter":{"title":"一六六","date":"2021-11-10T21:03:35.000Z","length":"14字","time":"1分钟","aside":false,"hash":1396559627}},{"url":"165","text":"\\n\\n学业不精荒于嬉，终是叶公好龙吟","frontmatter":{"title":"一六五","date":"2021-11-09T23:09:08.000Z","length":"14字","time":"1分钟","aside":false,"hash":26586168}},{"url":"164","text":"\\n\\n责任不负，能力越大越反动","frontmatter":{"title":"一六四","date":"2021-11-02T10:48:12.000Z","length":"11字","time":"1分钟","aside":false,"hash":-917957006}},{"url":"163","text":"\\n\\n公平才是最大的效率。舍此无它。","frontmatter":{"title":"一六三","date":"2021-11-02T09:27:20.000Z","length":"13字","time":"1分钟","aside":false,"hash":-1947202897}},{"url":"162","text":"\\n\\n人心！人心！人心！","frontmatter":{"title":"一六二","date":"2021-11-02T09:25:12.000Z","length":"6字","time":"1分钟","aside":false,"hash":1786452494}},{"url":"161","text":"\\n\\n以前有个女孩子问我，生活和生存的区别是什么？我说不上，也没在意，因为当时觉得格物致知是头一等事。几年来我偶尔会再想起这个问题，但都不了了之。直到最近，我想我明白了：生活就是生存加反思，哪怕这种反思既不彻底，又不一致。","frontmatter":{"title":"一六一","date":"2021-10-25T00:58:56.000Z","length":"96字","time":"1分钟","aside":false,"hash":-321438497}},{"url":"160","text":"\\n\\n之前总觉得山东拉面不好吃，今天才发现原来是我没用心煮","frontmatter":{"title":"一六〇","date":"2021-10-24T13:28:18.000Z","length":"25字","time":"1分钟","aside":false,"hash":2006565101}},{"url":"159","text":"\\n\\n大晚上听红旗颂又情不自禁。\\n\\n《功勋》是一部非常棒的电视剧，电影级别的制作，还原历史的主旨。（除了黄晓明演的那个单元，我为黄旭华老人抱大不平）\\n\\n历史总让我毫无保留地交付所有眼泪。\\n\\n不过理想是浪漫的，但现实是残酷的。我还应该继续改造我的思想。不应该只凭着一厢情愿和道德理想认识世界，那样只会成为一个空想主义者，辜负我数年来的科学训练。\\n\\n但这错误又在所难免。在自然界坚持唯物主义观点的人，也难免在人类社会中变得一厢情愿。\\n\\n希望接下来再多读点历史和哲学，也希望高中语文课本好不容易加进来的那几篇课文，老师能好好讲讲，而不是留作学生自学。这样，当这个青年有一天回首往事时不至于茫然自失、黯然作愧。","frontmatter":{"title":"一五九","date":"2021-10-10T00:53:06.000Z","length":"262字","time":"1分钟","aside":false,"hash":-470883650}},{"url":"158","text":"\\n\\n今天遇到一个好心的柬埔寨人帮我过了闸机。穿着佛黄色的长袍，外面套了一件羽绒服。他说他来法国是学哲学的（我估摸着就是佛学），其实连法语还不会说。我们就用简陋的英语聊天，他和我说柬埔寨有很多中国人，还说到西哈努克亲王也是在中国逝世的。我点点头，说他和中国老一辈领导人有深厚的友谊，中国和柬埔寨也是传统友邦。他问我有几个兄弟姐妹，我说我这一代人都是独生子女。他说这地铁来得慢，欧洲慢。我惊讶地问，柬埔寨很快吗？他摇摇头，说中国太快了。车来了，我和他道别。","frontmatter":{"title":"一五八","date":"2021-10-09T21:37:26.000Z","length":"201字","time":"1分钟","aside":false,"hash":-420575802}},{"url":"157","text":"\\n\\n法国人的舌头就像锉刀一样把每个英语音节削成一模一样的方块。煎熬啊...","frontmatter":{"title":"一五七","date":"2021-10-06T17:48:20.000Z","length":"31字","time":"1分钟","aside":false,"hash":752219040}},{"url":"156","text":"\\n\\n“不须放屁，试看天翻地覆”","frontmatter":{"title":"一五六","date":"2021-09-22T16:48:04.000Z","length":"10字","time":"1分钟","aside":false,"hash":-95377066}},{"url":"155","text":"\\n\\n晚上和我妈打羽毛球，碰上两个小孩打篮球。\\n\\n我妈和其中一个聊天：\\n\\n“你几年级哇？”\\n\\n“五年级”\\n\\n“你是篮球队的吗？”\\n\\n“是啊”\\n\\n“打什么位置？”\\n\\n“射手”\\n\\n“五年级怎么还没长个？他（指我）表弟打篮球的，六年级的时候都一米六了”\\n\\n“我后期发育”\\n\\n什么才是真正的 5v5 公平竞技啊","frontmatter":{"title":"一五五","date":"2021-09-18T16:21:49.000Z","length":"98字","time":"1分钟","aside":false,"hash":-1341324222}},{"url":"154","text":"\\n\\n毋忘国耻","frontmatter":{"title":"一五四","date":"2021-09-18T04:11:55.000Z","length":"4字","time":"1分钟","aside":false,"hash":855620117}},{"url":"153","text":"\\n\\n有些人狂还是有真才实学支撑的\\n\\n尤其是当他道破你引以为傲的知识体系时，你不以为耻，反跟着他一同反叛这荒芜的过去\\n\\n可恶啊，不服不行","frontmatter":{"title":"一五三","date":"2021-09-14T16:47:11.000Z","length":"58字","time":"1分钟","aside":false,"hash":-1754422000}},{"url":"152","text":"\\n\\n我造了个词：摸龙。指不务正业但比务正业更充实。","frontmatter":{"title":"一五二","date":"2021-09-09T09:41:54.000Z","length":"20字","time":"1分钟","aside":false,"hash":-713045628}},{"url":"151","text":"\\n\\n忌日感怀\\n\\n有思重九日 那堪度光阴\\n\\n既恨越洋鄙 因愧忘土情\\n\\n六方皆无就 往来俱待悉\\n\\n音容今犹在 伟业尚如意？\\n\\n指缺弄针巧 身失缚鸡力\\n\\n耳不辨是非 口难分诘屈\\n\\n六岁上学校 廿四始开蒙\\n\\n愿效故人志 光明永照心","frontmatter":{"title":"一五一","date":"2021-09-09T04:11:41.000Z","length":"84字","time":"1分钟","aside":false,"hash":-2021490974}},{"url":"150","text":"\\n\\n言出唯唯，想入非非","frontmatter":{"title":"一五〇","date":"2021-09-03T10:09:48.000Z","length":"8字","time":"1分钟","aside":false,"hash":-616004806}},{"url":"149","text":"\\n\\n经载道而非道。离之则叛，执之则迷。","frontmatter":{"title":"一四九","date":"2021-09-01T09:46:25.000Z","length":"14字","time":"1分钟","aside":false,"hash":-473843614}},{"url":"148","text":"\\n\\n隋文帝谓仆射高熲曰：我为百姓父母，岂可限一衣带水不拯之乎？——南史·陈纪下\\n\\n中华文化博大精深啊","frontmatter":{"title":"一四八","date":"2021-08-31T09:06:08.000Z","length":"40字","time":"1分钟","aside":false,"hash":6058478}},{"url":"147","text":"\\n\\n天下大乱，贤圣不明，道德不一。天下多得一察焉以自好。譬如耳目鼻口，皆有所明，不能相通。犹百家众技也，皆有所长，时有所用 。虽然，不该不遍，一曲之士也。判天地之美，析万物之理，察古人之全。寡能备于天地之美，称神明之容。是故内圣外王之道，暗而不明，郁而不发，天下之人各为其所欲焉以自为方。悲夫！百家往而不反，必不合矣！后世之学者，不幸不见天地之纯，古人之大体。道术将为天下裂。 ——《庄子·天下》","frontmatter":{"title":"一四七","date":"2021-08-27T10:46:16.000Z","length":"160字","time":"1分钟","aside":false,"hash":-1915849295}},{"url":"146","text":"\\n\\n前两天在家里看西游记续集，里面有个情节是孙悟空从阎王那里要回寇员外的魂魄。我顿时觉得奇怪，怎么中国的阎王还能管到印度土邦去？\\n\\n结果今天才发现原来阎王是印度人","frontmatter":{"title":"一四六","date":"2021-08-24T11:29:48.000Z","length":"73字","time":"1分钟","aside":false,"hash":-1930360675}},{"url":"145","text":"\\n\\n闲来读书，越发觉得近两年虚度了。书不是非读不可，但像我们这种被文字惯坏的人，不读书还有什么好呢？","frontmatter":{"title":"一四五","date":"2021-08-19T15:06:06.000Z","length":"43字","time":"1分钟","aside":false,"hash":1746915633}},{"url":"144","text":"\\n\\n今天读了几篇费孝通的乡土中国，好久没读这么小清新的文字了，上一次恐怕还是高中看的朱光潜。","frontmatter":{"title":"一四四","date":"2021-08-18T08:33:31.000Z","length":"41字","time":"1分钟","aside":false,"hash":-2052966195}},{"url":"143","text":"\\n\\n之前饭桌上有人说老舍投大明湖，我记得老舍是在北京殁的，于是信口说了一句是未名湖吧？\\n\\n结果今儿一查是太平湖...不学无术啊。","frontmatter":{"title":"一四三","date":"2021-08-17T09:22:09.000Z","length":"53字","time":"1分钟","aside":false,"hash":1602002398}},{"url":"142","text":"\\n\\n地恒动不止，而人不知，譬如人在大舟中，闭牖而坐，舟行不自觉也。——尚书纬·考灵曜","frontmatter":{"title":"一四二","date":"2021-08-13T03:40:12.000Z","length":"32字","time":"1分钟","aside":false,"hash":-1745729014}},{"url":"141","text":"\\n\\n学科学，史学史，泛又泛，钱生钱，局中局，人上人","frontmatter":{"title":"一四一","date":"2021-08-12T05:50:03.000Z","length":"18字","time":"1分钟","aside":false,"hash":1883640705}},{"url":"140","text":"\\n\\n如果我们因为胜利而忘乎所以，顺理成章地把结果归结为方法奏效，那么这和侥幸别无二异，这时我们比成功更需要失败。","frontmatter":{"title":"一四〇","date":"2021-07-30T02:32:05.000Z","length":"50字","time":"1分钟","aside":false,"hash":-1047215274}},{"url":"139","text":"\\n\\n生产把我们分开，而文艺本当把我们团结在一起。","frontmatter":{"title":"一三九","date":"2021-07-29T12:32:17.000Z","length":"20字","time":"1分钟","aside":false,"hash":515958482}},{"url":"138","text":"\\n\\n某人说“梦想是要有的，万一实现了呢？”这等于把理想主义者贬低为侥幸主义者、守株待兔者。理想，无论实现与否，作为一种向上的力量，能够阻遏堕落。正如保存价值的唯一办法，是添加新的价值。劳动是这样、传承是这样、扬弃也是这样。","frontmatter":{"title":"一三八","date":"2021-07-23T11:20:44.000Z","length":"94字","time":"1分钟","aside":false,"hash":-697298166}},{"url":"137","text":"\\n\\n礼貌中透着一股傲慢，高卢鸡是也。","frontmatter":{"title":"一三七","date":"2021-07-22T07:17:12.000Z","length":"14字","time":"1分钟","aside":false,"hash":313088114}},{"url":"136","text":"\\n\\n昨天读红楼，看到脂批引一段孟子的话：“君子欺以其方。”我今天突然明白，这眼花缭乱的数字不正是如此？智者上税，浑不自知也！","frontmatter":{"title":"一三六","date":"2021-07-22T05:34:47.000Z","length":"51字","time":"1分钟","aside":false,"hash":986758251}},{"url":"135","text":"\\n\\n这世上起码有两种骗人的把戏：一是文字游戏，一是数字游戏。\\n\\n而有的人两边都占了。","frontmatter":{"title":"一三五","date":"2021-07-19T08:42:41.000Z","length":"34字","time":"1分钟","aside":false,"hash":1426079935}},{"url":"134","text":"\\n\\n今天看到一个有趣的说法：\\n\\n“程序员有种种怪癖，其中一个是 20％的时间在写代码，剩下 80%的时间在欣赏自己写的代码。”\\n\\n虽然不是程序员，但我发现我 20%的时间在工作，80%的时间花在鼓起勇气工作-不想工作-陶醉于工作完成的愉悦中。\\n\\n也有可能是因为认真的时候，时间过得很快吧。","frontmatter":{"title":"一三四","date":"2021-07-15T11:13:19.000Z","length":"112字","time":"1分钟","aside":false,"hash":1556207244}},{"url":"133","text":"\\n\\n用人性来揣测信仰是对一个理想主义者最恶意的亵渎。\\n\\n一百年了，有的人从黑暗中掘出光明，有的人却依旧守着那个不升不落的白夜。他们心头布满的，不是一轮红日，而是那惨白刺眼的失焦的光。","frontmatter":{"title":"一三三","date":"2021-07-11T01:53:24.000Z","length":"80字","time":"1分钟","aside":false,"hash":785463206}},{"url":"132","text":"\\n\\n留在法国的同学说今晚法国人又开 soiree 了，甚至还放烟花，有人问是不是什么节日啊，于是我搜了搜历史上的大事件。\\n\\n国庆日前四天是另一个国庆日啊","frontmatter":{"title":"一三二","date":"2021-07-10T00:47:12.000Z","length":"61字","time":"1分钟","aside":false,"hash":206057790}},{"url":"131","text":"\\n\\n忽然发现我大可不必把对数字的憎恶迁延于统计，因为统计只是被数字异化的认识论。纯粹的量永远不能反映质，但数字确实仍在不断地吞噬这个世界，并把自己以更大的规模再生产出来。它作为最轻易就能获得的人类的通用语言，试图把一切契约还原为这种简单的形式。如果它还因此被人类赋予理性和公正的地位，它将成为部分人的信仰；如果它进一步成为美的代名词，它的信徒将献上他们的灵魂；如果它成为一切的唯一标准，那么一切都将化为乌有。","frontmatter":{"title":"一三一","date":"2021-07-09T04:50:06.000Z","length":"189字","time":"1分钟","aside":false,"hash":1160298527}},{"url":"130","text":"\\n\\n牌穷匕见","frontmatter":{"title":"一三〇","date":"2021-07-07T02:48:39.000Z","length":"4字","time":"1分钟","aside":false,"hash":911742785}},{"url":"129","text":"\\n\\n今天游泳超时四分钟罚了 10 块钱，出门哈喽单车锁舌没弹出来直接扣钱，再找了一辆骑回宾馆花了 15 分钟零 9 秒...太背了","frontmatter":{"title":"一二九","date":"2021-07-06T15:45:49.000Z","length":"50字","time":"1分钟","aside":false,"hash":886169570}},{"url":"128","text":"\\n\\n“于是，马克思发表意见了，他的意见是和所有他的前人直接对立的。在前人认为已有答案的地方，他却认为只是问题所在。他认为，这里摆在他面前的不是无燃素气体，也不是火气，而是氧气；这里的问题不是在于要简单地确认一种经济事实，也不是在于这种事实与永恒公平和真正的道德相冲突，而是在于这样一种事实，这种事实必定要使全部经济学发生革命，并且把理解全部资本主义生产的钥匙交给那个知道怎样使用它的人。”——恩格斯","frontmatter":{"title":"一二八","date":"2021-07-05T14:28:36.000Z","length":"179字","time":"1分钟","aside":false,"hash":381602264}},{"url":"127","text":"\\n\\n伟大征程在新闻联播发布剪辑版的时候，忽然听见唢呐配合东方红的旋律，眼前顿时浮现“雄鸡一唱天下白”的意象。今天特意去完整版找这个节目，原来唢呐只吹了前两句，不免觉得可惜。但回头想想，东方总会红，太阳照常升，天道唯信也；至于人道，一逝不返，唯有前进不负过去，唯有留白尊重未来。","frontmatter":{"title":"一二七","date":"2021-07-02T18:24:51.000Z","length":"120字","time":"1分钟","aside":false,"hash":2072207698}},{"url":"126","text":"\\n\\n昨天突发奇想但是累得发不出来：\\n\\n一日为诗，终身为赋。\\n\\n好像没啥道理","frontmatter":{"title":"一二六","date":"2021-07-02T01:30:42.000Z","length":"28字","time":"1分钟","aside":false,"hash":-1912716760}},{"url":"124","text":"\\n\\n不忘初心，牢记使命；永久奋斗，革命到底。","frontmatter":{"title":"一二四","date":"2021-06-30T18:00:21.000Z","length":"16字","time":"1分钟","aside":false,"hash":2112646676}},{"url":"123","text":"\\n\\n美梦不过夜，噩梦连续剧。\\n\\n噩梦该不会是云天明童话吧。","frontmatter":{"title":"一二三","date":"2021-06-25T23:26:35.000Z","length":"22字","time":"1分钟","aside":false,"hash":1286626236}},{"url":"122","text":"\\n\\n国民党 1927 年就死了，但直到 2021 年还没埋。","frontmatter":{"title":"一二二","date":"2021-06-25T17:01:03.000Z","length":"16字","time":"1分钟","aside":false,"hash":-886384060}},{"url":"121","text":"\\n\\n丈夫岂惧死？只恨正青春。","frontmatter":{"title":"一二一","date":"2021-06-25T16:21:24.000Z","length":"10字","time":"1分钟","aside":false,"hash":-1879959840}},{"url":"120","text":"\\n\\n校本教材真良心，感受到数学的善意，并从数学中感受到法语的善意。\\n\\n（中文教材什么时候能站起来）","frontmatter":{"title":"一二〇","date":"2021-06-19T10:24:45.000Z","length":"40字","time":"1分钟","aside":false,"hash":121444741}},{"url":"119","text":"\\n\\n平生第一次听说南烛这种植物。常山人管叫乌饭叶，用来泡米饭，做成乌饭。身为衢州人竟然连眼皮子底下的东西都不知道。\\n\\n更想到当年润之路过金华的时候，问起衢县三怪，周围的地、县委领导竟无一人知道，愈发自愧了。","frontmatter":{"title":"一一九","date":"2021-06-15T14:13:49.000Z","length":"89字","time":"1分钟","aside":false,"hash":11622612}},{"url":"118","text":"\\n\\n体育就是战争的延伸，团队还是那个团队。胜利靠的是组织，而不是某个高素质的兵王。凭几个高级外援，凭请几个王牌教练就想屹立球坛，喃喃说：“我保证：永不假赛！甭管黑人白人，能踢好球的就是好人！”","frontmatter":{"title":"一一八","date":"2021-06-08T02:09:06.000Z","length":"81字","time":"1分钟","aside":false,"hash":-1324719651}},{"url":"117","text":"\\n\\nSchumpeter 认为资本主义经济周期循环源于创新，把创新解释成为一种创造性的破坏。由创新造成了上一次的萧条并开启了下一周期的繁荣。\\n\\n也算是一篇漂亮文章了。","frontmatter":{"title":"一一七","date":"2021-06-02T21:14:53.000Z","length":"65字","time":"1分钟","aside":false,"hash":1438960499}},{"url":"116","text":"\\n\\n人们自己创造自己的历史，但是他们并不是随心所欲地创造，并不是在他们自己选定的条件下创造，而是在直接碰到的、既定的、从过去承继下来的条件下创造。一切已死的先辈们的传统，像梦魇一样纠缠着活人的头脑。——马克思","frontmatter":{"title":"一一六","date":"2021-06-01T19:01:11.000Z","length":"92字","time":"1分钟","aside":false,"hash":-1249399807}},{"url":"115","text":"\\n\\n[网页链接](https://zhuanlan.zhihu.com/p/354916372)\\n\\n与我个人观点基本一致的一篇文章。浅谈自己对这个问题的理解。马克思的唯物唯心划分，其实是对当时西方的思想界的分析批判。马克思是否对东方哲学有所了解，我不清楚。但是我对高中教材中关于唯心和唯物的某些判断一直心存疑窦。譬如从笛卡尔我思故我在这句话判断它是主观唯心主义，这显然是不对的。笛卡尔从思维的存在性反推出我的存在性，是因为他坚信没有存在就不会有思维，这相反是一个相当唯物的观点。（但这并不是说笛卡尔最终不是唯心主义，毕竟还能找到其他更可靠的论据。）而教材对中国古今许多哲学家都做了唯物唯心的种种划分，以至于在上完思想政治的那一瞬间，我竟以为我所学习的对这些例子的划分，是我已经彻底了解掌握他们后得出的结论，甚至比这更自负——幻生出一种曾经沧海难为水的错觉，认为除了马克思主义，其他都是浮云。（这本身是反辩证法的，因为赞同要从怀疑从来，反对要从熟悉中来）这种狂妄往后便一直未经反思，直到前两个月看到一本讲中国古代哲学的法国讨论班教材，我才发现我几乎都不认识（对先人再表羞愧），顿时觉得，高中教材从只言片语出发，就为各个哲学家毕生经营排了三六九等，确实不足。（当然教材的任务并不是要教导真理，否则没有完美的教材，而是探索真理的怀疑精神。教材有删改是天生的不足，但不对删改作反思则是后天的不足）人的思维何尝不爱如此，归类本是最后一步，这样却成了一种精致的偷懒。\\n\\n润之说，马克思主义千头万绪，总结起来就一句话：造反有理。我想这是强调历史唯物主义，强调阶级斗争的一方面。造反，本质上就是遵循矛盾运动规律，推动矛盾运动的发展，怎么推动？就是实践。到中国的语境下，就是知行合一。马克思说，关键在于改造世界。从中国的传统上看，从古至今不缺改造世界的，或说经世致用的思想。私以为中国的哲学，处世是高于治学的，行有余力则以学文，绝不是为学而荒废了行。无论避世的或真或假，都是作为用世的对立而非其他。因而在改造世界这一观点上，古人都是执着的（当然这种改造，并非是进化论意义上的）。仅凭这点而言，我想相比他反对的那些纯粹的思想家，马克思会更加认同我们的古人。这也许是为什么，即便不那么“唯物”，中国思想天生能为东渐的马学留有一块余地。因为讲知行合一才是根本，连存在与思维的地位关系，也是为着这个最终的结论而服务的。\\n\\n一点感悟，欢迎交流。","frontmatter":{"title":"一一五","date":"2021-05-28T09:07:33.000Z","length":"875字","time":"3分钟","aside":false,"hash":1887485049}},{"url":"114","text":"\\n\\n用法语写的数学书似乎更通顺，数学中有没有语言沙文主义呢？","frontmatter":{"title":"一一四","date":"2021-05-22T17:42:56.000Z","length":"26字","time":"1分钟","aside":false,"hash":-1624287393}},{"url":"113","text":"\\n\\n什么书常读常新？数学书","frontmatter":{"title":"一一三","date":"2021-05-18T21:08:22.000Z","length":"10字","time":"1分钟","aside":false,"hash":-967316928}},{"url":"112","text":"\\n\\n本来世界上就没什么魔法，只有聪明的人才会被咒语使唤。——黑客实践课有感","frontmatter":{"title":"一一二","date":"2021-05-15T16:16:34.000Z","length":"31字","time":"1分钟","aside":false,"hash":35312781}},{"url":"111","text":"\\n\\n谷歌文档匿名身份怎么都是臭鼬鼩鼱一类的动物","frontmatter":{"title":"一一一","date":"2021-05-11T19:37:28.000Z","length":"21字","time":"1分钟","aside":false,"hash":907507772}},{"url":"110","text":"\\n\\n通宵看恰同学少年\\n\\n伟大的生命本身就是一部历史，这部历史承载着见证者的生命。\\n\\n仿佛连接上了卡拉","frontmatter":{"title":"一一〇","date":"2021-05-09T05:24:11.000Z","length":"42字","time":"1分钟","aside":false,"hash":-1559715251}},{"url":"109","text":"\\n\\n不良人 4 被改得面目全非\\n\\n苗疆变成了娆疆，巫王变成了毒公，蛊王变成了虺王，蛊全改成了虫，我服了！","frontmatter":{"title":"一〇九","date":"2021-05-07T21:00:55.000Z","length":"41字","time":"1分钟","aside":false,"hash":-2113935075}},{"url":"108","text":"\\n\\n不得不说统计物理真是神奇，改变了我对物理的看法，更改变了我对统计的看法。理想与现实的辩证统一。搞统计很容易陷入实用主义，不仅是统计，小到修身、大到治国都是如此。怎样避免陷入实用主义，是个很大的问题，怎样判断实用主义的自欺欺人，更是个大问题。","frontmatter":{"title":"一〇八","date":"2021-04-28T21:29:34.000Z","length":"108字","time":"1分钟","aside":false,"hash":-644653124}},{"url":"107","text":"\\n\\n拼上全部活成笑话，这才是用生命致敬喜剧\\n\\n另外小兵张嘎电影版可高明多了","frontmatter":{"title":"一〇七","date":"2021-04-26T19:39:13.000Z","length":"32字","time":"1分钟","aside":false,"hash":944532586}},{"url":"106","text":"\\n\\n好家伙，我居然碰上了一个 gdb 的 bug","frontmatter":{"title":"一〇六","date":"2021-04-21T17:07:14.000Z","length":"14字","time":"1分钟","aside":false,"hash":-1019575641}},{"url":"105","text":"\\n\\n劝大家谨慎更新安卓 11，别问我为什么","frontmatter":{"title":"一〇五","date":"2021-04-20T12:13:49.000Z","length":"16字","time":"1分钟","aside":false,"hash":-256494386}},{"url":"104","text":"\\n\\n资本把人变成机器，科技把机器变成人；从人身上异化出来的东西异化人，这就是赛博朋克。","frontmatter":{"title":"一〇四","date":"2021-04-19T10:28:32.000Z","length":"37字","time":"1分钟","aside":false,"hash":1826748305}},{"url":"103","text":"\\n\\n上午学长和我说面试官问了他一堆概率问题，结果他骰子的期望还口算了半天。\\n\\n中午碰到牛跟他说了这事儿，牛说这不是三吗，学长凉了，我说你给学长留点面子。\\n\\n下午我睡醒以后，猛然发现:\\n\\n骰子的期望是 3.5。\\n\\n三个憨憨...","frontmatter":{"title":"一〇三","date":"2021-04-16T16:33:11.000Z","length":"89字","time":"1分钟","aside":false,"hash":1391999055}},{"url":"102","text":"\\n\\n黑魔法课第一个挑战任务是黑进一个网页并在上面留下自己的名字。结果有一组同学不仅写上了自己的名字还把别人的名字给抹去了。\\n\\n而还在上初级黑魔法防御课的我只能在一旁默默鼓掌","frontmatter":{"title":"一〇二","date":"2021-04-16T08:44:08.000Z","length":"80字","time":"1分钟","aside":false,"hash":767303468}},{"url":"101","text":"\\n\\n感觉法语考出来以后说话码字都顺畅多了，oh~虚荣的力量","frontmatter":{"title":"一〇一","date":"2021-04-15T23:20:34.000Z","length":"24字","time":"1分钟","aside":false,"hash":-941765332}},{"url":"100","text":"\\n\\n世界变化真快啊，兴许过不了几年，法律就会开放人类基因编辑技术。毕竟你不编辑，核辐射就会替你编辑。到时候医疗、生物、食品、殡葬行业又会是一片欣欣向荣。噢对了，三战也可以提上日程了，毕竟亦无忌器之忧了。是等蘑菇云升起，还是赛博朋克先来临？","frontmatter":{"title":"一〇〇","date":"2021-04-14T16:38:07.000Z","length":"103字","time":"1分钟","aside":false,"hash":-669943902}},{"url":"99","text":"\\n\\n分享阿鲲的专辑《觉醒年代 电视剧原声大碟》: [网页链接](http://music.163.com/album/124487045/?userid=289878385) (来自@网易云音乐)\\n\\n借着这部剧，重新认识了两位熟悉的陌生人和一群陌生的年青人。","frontmatter":{"title":"九九","date":"2021-04-06T15:54:54.000Z","length":"64字","time":"1分钟","aside":false,"hash":-716642666}},{"url":"98","text":"\\n\\n分享闰心创建的歌单「法语歌的历史记忆：古典至二战」: [网页链接](http://music.163.com/playlist/6682569587/289878385/?userid=289878385) (来自@网易云音乐)","frontmatter":{"title":"九八","date":"2021-03-28T00:12:53.000Z","length":"42字","time":"1分钟","aside":false,"hash":-145819184}},{"url":"97","text":"\\n\\n分享 André Dassary 的单曲《Marechal nous voila》: [网页链接](http://music.163.com/song/523926764/?userid=289878385) (来自@网易云音乐)\\n\\n法兰西国（39-45）：“一个兼具德治与法治的理想国家”。","frontmatter":{"title":"九七","date":"2021-03-27T20:56:10.000Z","length":"49字","time":"1分钟","aside":false,"hash":1980764859}},{"url":"96","text":"\\n\\n我以前确实没理解什么叫珍爱生命我学 python。\\n\\n现在看来 C 语言编程无异于慢性自杀","frontmatter":{"title":"九六","date":"2021-03-26T19:08:16.000Z","length":"34字","time":"1分钟","aside":false,"hash":-1490425547}},{"url":"95","text":"\\n\\n好家伙，普朗克发现了两个常数：k 和 h。并把前者命名为玻尔兹曼常数。\\n\\n高情商","frontmatter":{"title":"九五","date":"2021-03-21T17:17:36.000Z","length":"32字","time":"1分钟","aside":false,"hash":-1810960763}},{"url":"94","text":"\\n\\n乘骐骥以驰骋兮，来吾道夫先路！","frontmatter":{"title":"九四","date":"2021-03-20T19:11:47.000Z","length":"13字","time":"1分钟","aside":false,"hash":27300590}},{"url":"93","text":"\\n\\n即便如鲁迅先生那样受过严格国学训练的大家，遣词造句也难免袭染些日式的语法。可见母语不是天生就会的，却是天生给人盲目自信的；可见语言为何必要与文学结合成语文，大学不继续语文教育是不合适的；可见留学并非无害的，留在中国是无可厚非的；可见不接地气是不行的，雅俗共赏是不容易的。","frontmatter":{"title":"九三","date":"2021-03-19T00:36:58.000Z","length":"125字","time":"1分钟","aside":false,"hash":763837899}},{"url":"92","text":"\\n\\n越学越玄，越玄越学\\n\\n搞不好哪天，去投马列。\\n\\n突然明白为啥有些马克思主义博士生的本科都是些千奇百怪的专业了。","frontmatter":{"title":"九二","date":"2021-03-16T18:14:55.000Z","length":"47字","time":"1分钟","aside":false,"hash":-950729064}},{"url":"91","text":"\\n\\n朝鲜地小民偷，古为人属，君臣贪残，宇内无比——陈独秀 一九一四年","frontmatter":{"title":"九一","date":"2021-03-13T10:13:44.000Z","length":"26字","time":"1分钟","aside":false,"hash":-896208905}},{"url":"90","text":"\\n\\n接上一条。C 语言在 hello world 处就给我了一个下马威。好家伙。fgets 好损。","frontmatter":{"title":"九〇","date":"2021-03-12T12:06:27.000Z","length":"26字","time":"1分钟","aside":false,"hash":-1428222582}},{"url":"89","text":"\\n\\n学 python 的时候：print(''hello world'')\\n\\n学 java 的时候:外面套个 class main，system.out.print(''hello world'')\\n\\n学 c:安装 VMware，在虚拟机上安装 ubunbu，用 text editor 写下.h 文件、.c 文件、makefile 文件，用 gcc 编译，在古朴的 terminal 中成功运行 hello world\\n\\n喜极而泣","frontmatter":{"title":"八九","date":"2021-03-11T11:13:27.000Z","length":"71字","time":"1分钟","aside":false,"hash":573193698}},{"url":"88","text":"\\n\\n分享 MevrouwManon 创建的歌单「电视剧《觉醒年代》部分配乐」: [网页链接](http://music.163.com/playlist/6609488233/249877987/?userid=289878385) (来自@网易云音乐)\\n\\n人不可貌相，BGM 不可只看名字","frontmatter":{"title":"八八","date":"2021-03-09T22:27:05.000Z","length":"51字","time":"1分钟","aside":false,"hash":793760483}},{"url":"87","text":"\\n\\n这学期的法语课：penser et representer la nature.\\n\\n我以为的内容：日月山水花鸟虫鱼\\n\\n现实：支持/反对核武器、人造肉、转基因？","frontmatter":{"title":"八七","date":"2021-03-08T16:59:54.000Z","length":"41字","time":"1分钟","aside":false,"hash":1425897709}},{"url":"86","text":"\\n\\n其实这个剧明明是个严肃话题，还是有很多彩蛋。譬如第一集衣着破落的陈独秀抛出暴论试探学生，然后在李大钊掩护下躲开了愤怒的学生，最后在小树林中坦诚身份，二人一见如故。颇有张良纳履的味道，典型的中国式桥段。\\n\\n后面陈独秀冲李大钊说我知道燕赵多义士。瞬间跳戏三国，好家伙这次是名副其实。\\n\\n还有蔡元培三顾茅庐请陈独秀出山，明摆着了。明知是套路，但就是好看。\\n\\n亚东图书馆馆长汪孟邹也是个可爱的配角，总给陈独秀打圆场。浪漫的人背后大概总需要一个踏实的伙伴。这搭档也是老样式了。\\n\\n这部剧还有好多好多名场面，导演拍摄手法也很现代，不乏很多魔幻现实的镜头，背景音乐分三种：严肃、轻快、激昂。中西都用。陶然亭陈独秀会钱玄同配流水绝了！河南春晚后的又一视听盛宴。总算和国内接上一次轨了。\\n\\n幸甚至哉，歌以咏志。","frontmatter":{"title":"八六","date":"2021-03-06T23:26:18.000Z","length":"304字","time":"2分钟","aside":false,"hash":-839902198}},{"url":"85","text":"\\n\\n一口气追了十三集觉醒年代，有好多感慨。\\n\\n各种各样的细节和隐喻就不提了，这剧确实让我又对陈独秀这位熟悉的陌生人有了新的了解。\\n\\n安徽人，确实挺秀的，就是照片上看起来木的很，不知道是不是导演组加戏。\\n\\n两个在上海滩街头的孩子，让人瞬间想到另外一对上海滩流浪的兄弟。\\n\\n看了下出品方是安徽省委和北京市委宣传部，所以自然夹带了些安徽的私货，譬如荷叶黄牛蹄。北京私货就不说了，都快成北大官方宣传片了。\\n\\n钱玄同确实是个掀屋顶的主，蔡元培是个狡兔，胡适风华正茂，不过总提他白话诗白话文，也没具体介绍几个例子，多半是因为炸弹和蝴蝶确显幼稚，抛开时代背景以外拿不出手。\\n\\n其实最意想不到的还是陈独秀父子关系的演绎，不知道有没有史实支撑。\\n\\n总体上看似回顾历史，其实还是在讲当下的故事。百年前讲的是新文化，多半是破除；现在再谈文化自信，多半是传承。借古喻今我不反对，就是\\n\\n润之和豫才的镜头给的太少啦！每帧都很宝贵。上三张图。蓑衣润寰、青衫润之、抄碑鲁迅。","frontmatter":{"title":"八五","date":"2021-03-06T22:43:52.000Z","length":"367字","time":"2分钟","aside":false,"hash":-1666904557}},{"url":"84","text":"\\n\\n今天被大牛点拨，才发现 map 老师也是混元功法高手，掌门不论吧，至少比那两个年轻人高到不知道哪里去了。\\n\\n要想生活过得去，怎能脸上没乌青\\n\\n马老师，不过是把实话说出来了。这波啊，这波是童叟无欺。结果，好嘛，欺负我这个 69 岁的老实人，英国大力士都扳不过的我，被你两句锐评讲得翻不了身，官方亲自下场，不讲武德啊！\\n\\n幸亏严顺开有迅哥儿背书，否则早就被赵太爷割了舌头，看它能喊出什么来。","frontmatter":{"title":"八四","date":"2021-03-02T00:21:32.000Z","length":"161字","time":"1分钟","aside":false,"hash":2104331271}},{"url":"83","text":"\\n\\n分享木村弓的单曲《いつも何度でも (永远同在)》: [网页链接](http://music.163.com/song/443860/?userid=289878385) (来自@网易云音乐)\\n\\n日本——希望你振作、勇敢、包容自己。\\n\\n韩国——希望你谦虚、自尊。\\n\\n越南——希望你谦虚、自爱，最好找回初心。\\n\\n中国——希望你找回初心，试着启发他人。\\n\\n不是我们来原谅你，在此之前，你敢不敢原谅你自己？\\n\\n不是我们来批评你，在此之前，你敢不敢自我批评？\\n\\n必要的话，可以启发，但终究不能代替自省。","frontmatter":{"title":"八三","date":"2021-02-25T23:51:32.000Z","length":"143字","time":"1分钟","aside":false,"hash":-622581709}},{"url":"82","text":"\\n\\n对法语歌重新燃起希望\\n\\n果然歌曲和歌手无关，跟时代有关。\\n\\n分享 Barbara 的单曲《Gottingen》: [网页链接](http://music.163.com/song/2306019/?userid=289878385) (来自@网易云音乐)","frontmatter":{"title":"八二","date":"2021-02-25T00:36:08.000Z","length":"50字","time":"1分钟","aside":false,"hash":-895058043}},{"url":"81","text":"\\n\\n真心推荐大家看看河南春晚。\\n\\n男儿有泪不轻弹，只是未到动心处。\\n\\n传统文化、抗疫、东方红。\\n\\n什么叫做文艺的政治性？\\n\\n什么叫做政治任务？\\n\\n据说央视抄了十几年作业了，还没抄明白。\\n\\n1964 年东方红音乐剧首映\\n\\n2021 年河南春晚节目东方为什么红向它致敬\\n\\n（本来想放图的，嫌麻烦，诸位自行搜索 b 站吧）\\n\\n我从来没有对异乡怀有如此的归属。山东没有做到的事，河南做到了。\\n\\n中央台做不到的，地方台做到了。据说这晚会只花了五百万，排练了两个月。节目戏词可见一斑：我一不为官、二不为宦，为的是那大宋江山和黎民。\\n\\n官宦能成何事？还不是看人民群众！","frontmatter":{"title":"八一","date":"2021-02-23T15:27:41.000Z","length":"216字","time":"1分钟","aside":false,"hash":-454113225}},{"url":"80","text":"\\n\\n我给最后一课戛然而止的安静拉回现实，看见光标在我面前闪烁；知道已是期末将近时候。我在蒙胧中，又隐约听到先前的老师慢条斯理的嗓音，宛转地总结宏旨、展望未来，扬起神奇的帆，搅动着我的脑海。我在这起伏荡漾中，感到启发和舒适，对从期初浪到期末的疑虑，全给这充满默示的夜一扫而空了，只觉得眼耳身心歆享了憧憬和良缘，都醉醺醺的在空中蹒跚，豫备给考试周的我以无限的幸福。","frontmatter":{"title":"八〇","date":"2021-02-22T21:38:10.000Z","length":"162字","time":"1分钟","aside":false,"hash":-745857899}},{"url":"79","text":"\\n\\nJust saw some discussion on the difference between non-deterministic algorithm and random algorithm. And I found a very interesting metaphor saying\\n\\n''Deterministic: I choose.\\n\\nNon-deterministic: Someone choose for me.\\n\\nRandom: No one choose.''\\n\\nwhere choice seems to be a synonym of decision, which suddenly reminds me of the famous Axiom of Choice. Regardless of its fancy name, it seems that le truc is introduced by the mathematicians to overcome their decidophobia.\\n\\nNo it's not a joke of OCD. On the contrary, it involves our basic acknowledgements. What means a decision? What means freedom? What means fate? What means randomness? This constructs a main part of western philosophy. In this metaphor, what is the difference between Someone and I? If no one choose then how? Here, someone cannot mean the others I don't and I can't know, it means something beyond me and my species, yes like the western god. Another formulation of non-deterministic Turing Machine is an ordinary Turing Machine equipped by an extra hint occuring somehow. The machine simply checks if the hint is right or wrong. This formulation obviously made a reservation for the God. A famous saying goes: only children make choices, the adult wants them all. But maybe the fact is: only humans are concerned about choice, the God does not even care. The saying, actually reflects the dream that human wants to transcend its pitiful finiteness and to imitate the God. The Axiom of choice, together with the mysterious non-deterministic Turing machine and others, are all such things. However, any such effort will push the God from the heaven into the void in the end.","frontmatter":{"title":"七九","date":"2021-02-21T23:01:53.000Z","length":"277字","time":"1分钟","aside":false,"hash":-260207307}},{"url":"78","text":"\\n\\n推荐一部 2000 年的情景喜剧，一手托两家。英达导演，梁左编剧。没有笑声罐头。","frontmatter":{"title":"七八","date":"2021-02-15T09:36:41.000Z","length":"30字","time":"1分钟","aside":false,"hash":204726948}},{"url":"77","text":"\\n\\n记得初中科学有道题考月相：\\n\\n月上柳梢头，人约黄昏后是阴历几号\\n\\n我就用上上上西西下下下东东的方法推出是十五。\\n\\n结果今天偶然翻到这句话，发现诗的题目是《生查子·元夕》\\n\\n出成一道科学题果然只能考考我这自作多情的丈育了。\\n\\n读完发现这诗还挺应景的。","frontmatter":{"title":"七七","date":"2021-02-14T01:07:53.000Z","length":"105字","time":"1分钟","aside":false,"hash":221415308}},{"url":"76","text":"\\n\\n积雪天：明亮，静谧，冷清","frontmatter":{"title":"七六","date":"2021-02-10T18:10:36.000Z","length":"9字","time":"1分钟","aside":false,"hash":-1010644074}},{"url":"75","text":"\\n\\n电气，日语舶来词。电指电，气指循环的物质。我以前一直没理解这个气字。","frontmatter":{"title":"七五","date":"2021-02-05T10:09:07.000Z","length":"29字","time":"1分钟","aside":false,"hash":985572814}},{"url":"74","text":"\\n\\n中国地名大会太好看了。\\n\\n学到一个词：表扬与自我表扬。\\n\\n想到两个词：改流归土，家庭联产承包责任制","frontmatter":{"title":"七四","date":"2021-02-02T17:54:56.000Z","length":"40字","time":"1分钟","aside":false,"hash":-1055001153}},{"url":"73","text":"\\n\\n马克思自白，对幸福的理解：斗争；对不幸的理解：屈服。\\n\\n毛曾经说：与天奋斗，其乐无穷；与地奋斗，其乐无穷；与人奋斗，其乐无穷。\\n\\n现在我明白：与己奋斗，其乐亦无穷。","frontmatter":{"title":"七三","date":"2021-01-28T16:52:42.000Z","length":"63字","time":"1分钟","aside":false,"hash":1748534799}},{"url":"72","text":"\\n\\n身有涯而心无穷，以身逐心殆矣，以心养身可也。","frontmatter":{"title":"七二","date":"2021-01-28T14:23:33.000Z","length":"19字","time":"1分钟","aside":false,"hash":-1946639675}},{"url":"71","text":"\\n\\n成天插科打诨，偶尔凝视深渊","frontmatter":{"title":"七一","date":"2021-01-27T21:25:38.000Z","length":"12字","time":"1分钟","aside":false,"hash":-1639889035}},{"url":"70","text":"\\n\\n狗屁不通诗\\n\\n敏感而刁钻，多愁且虚妄\\n\\n自负存侥幸，懦弱恨不时\\n\\n有心敢共鸣，无力爱自嘲","frontmatter":{"title":"七〇","date":"2021-01-26T23:06:00.000Z","length":"35字","time":"1分钟","aside":false,"hash":1881307047}},{"url":"69","text":"\\n\\n真想躲开社会分工的目光，好叫我永远徜徉在幽灵般的概率海洋。我不敢坍缩进那浊世，与那假清高何异？\\n\\n一面是脱产者焦虑，一面又是异化物恐惧。\\n\\n不忘初心，不在温室在尘世。","frontmatter":{"title":"六九","date":"2021-01-26T22:36:44.000Z","length":"71字","time":"1分钟","aside":false,"hash":-1981464061}},{"url":"68","text":"\\n\\n我曾经纠结的问题：解决不了的遗忘了，解决了的也遗忘了。我长大了。","frontmatter":{"title":"六八","date":"2021-01-26T18:08:04.000Z","length":"28字","time":"1分钟","aside":false,"hash":-730072014}},{"url":"67","text":"\\n\\n他们今天砍树，明天吃人，一点一点摧毁人民共和国的基业。\\n\\n而我除了悲愤，什么都做不了。\\n\\n一万年太久，何时革命？！","frontmatter":{"title":"六七","date":"2021-01-24T00:48:21.000Z","length":"45字","time":"1分钟","aside":false,"hash":683708504}},{"url":"66","text":"\\n\\n苦不苦，想想红军两万五；累不累，想想革命老前辈。","frontmatter":{"title":"六六","date":"2021-01-23T23:35:49.000Z","length":"20字","time":"1分钟","aside":false,"hash":-897810609}},{"url":"65","text":"\\n\\n四维时空图真是个伟大的发明，它告诉你没有谁能留在原地。多么相近的两点，都会被时空无情的撕开。而人的交流，绝不至于达到光速，因而每个人的世界都被限制在自身的那个更窄的“光”锥里，这“光”锥之外的事件，就如同真光锥以外的事件，是我们宇宙之外，只存在于想象中的东西。这真是有趣至极了，你能画出它，但你却无法理解它。\\n\\n这就是鲁迅口中的可怜的厚障壁么？","frontmatter":{"title":"六五","date":"2021-01-20T21:59:54.000Z","length":"151字","time":"1分钟","aside":false,"hash":-1024984996}},{"url":"64","text":"\\n\\n这么多年过去了，心头那个难解的哑谜总算找到了谜底。登时玉宇澄清，再也不用费劲地周旋于“加急名单”的阴阳怪气和这个“懂得都懂”的该死的滑稽脸上了。\\n\\n是非皆后验，境界定高低。\\n\\n下下人有上上智，上上人有没意智。\\n\\n不过把话挑明了说，似乎并不合这古老国度的古老传统。亦或是，在数千年的教化之下，我们已经沉浸于这种猜谜索隐的乐趣？\\n\\n这是一种残忍的乐趣。这是一种无奈的宽慰。\\n\\n我们本可以避免这种无奈的迂回，正如那低效的推杯换盏并非真情，恰是言不由衷的体现。一切的确可以尽在不言，但这绝非托辞。欲言则言，欲止则止，不亦快哉？","frontmatter":{"title":"六四","date":"2021-01-04T21:31:06.000Z","length":"222字","time":"1分钟","aside":false,"hash":-1490259555}},{"url":"63","text":"\\n\\n20 年过去了，疫情封城，回不了家。去年只听了 100 多小时的网易云，却看了近 700 个小时的 b 站。书么几乎没读，文章几乎没写，想法几乎没有，生活之郁闷，可见一斑。菜么会烧几道了，奶酪也能咽下几口了，生物钟也明显后调了。法语能听懂一点了，法国的风景看了一点，但原先的那种憧憬完全不见了。这里的冬天鬼一样的多雨，直想逃离。我的眼耳口鼻心都不属于这里。我是个没有记忆没有视野没有心境的时空中的异乡人。历史叫我迷惘，未来击穿了我此在的空虚。\\n\\n黑夜给了我黑色的眼睛，我却忘记了黑夜在哪里。","frontmatter":{"title":"六三","date":"2021-01-01T01:56:01.000Z","length":"207字","time":"1分钟","aside":false,"hash":2120125533}},{"url":"62","text":"\\n\\n楚凤三年不鸣，只等一鸣惊人，怎料竟已哑了。","frontmatter":{"title":"六二","date":"2020-12-31T13:48:24.000Z","length":"18字","time":"1分钟","aside":false,"hash":-1151174324}},{"url":"61","text":"\\n\\n君子以独立不惧，遁世无闷。","frontmatter":{"title":"六一","date":"2020-12-22T00:03:09.000Z","length":"11字","time":"1分钟","aside":false,"hash":-1100776535}},{"url":"60","text":"\\n\\n雾山五行，衢州出品。哈哈哈哈哈哈哈！","frontmatter":{"title":"六〇","date":"2020-12-20T00:10:51.000Z","length":"15字","time":"1分钟","aside":false,"hash":1505587777}},{"url":"59","text":"\\n\\n看来物理本就是玄学妄语，托数学的福，幸有些用世之地。\\n\\n数学也不过奇技淫巧，托物理的福，幸有些用武之地。\\n\\n本都是些迷信，全赖自然撮合，恰能沟通主客之境，便显得神通。\\n\\n于是所谓科学家哲学家并不比原始的巫师天官高明，在其位谋其政而已。唯一不同的，在于这种巫术不再是某种特权秘籍，不再为少数人服务，而能传播开来，走向大众。这不是巫术的进步，而是众生的解放。\\n\\n这一点又让我联想到文字不再是通天的媒介，而只是系人的工具。从神器到俗具，本质没变，只是受众的扩大，揭去了神秘的面纱。所谓高雅之物在这通俗之路上趋向末流，以及由此产生的复古潮，只是小资轻蔑普罗大众的臆想罢了，我也深受其害。\\n\\n从来不存在什么古典黄金时代，尧舜禹皆凡人也，固有治水之功，至于禅让之德，非力不可取。春秋战国盖贵族式微，古之司官，穷途末路，兴学以恰饭，思潮普及，而后有百家争鸣。进步者，非一人之学问钻进，乃大众解放也。","frontmatter":{"title":"五九","date":"2020-12-18T11:44:55.000Z","length":"339字","time":"2分钟","aside":false,"hash":957273975}},{"url":"58","text":"\\n\\n我好好反思了一下，我对语言的热爱是片面的，不妨说是对语音和语法的热爱。语音学很像化学，讲元素讲变化讲搭配组合。语法讲规则。但是词汇，讲恰当讲例外，每个词都是一段故事。词汇太多，故事太碎，也就罢了。当然，母语除外。","frontmatter":{"title":"五八","date":"2020-12-18T08:36:12.000Z","length":"92字","time":"1分钟","aside":false,"hash":-427661452}},{"url":"57","text":"\\n\\n什么感应受孕的传说，到头来都是野合借种","frontmatter":{"title":"五七","date":"2020-12-14T17:45:39.000Z","length":"18字","time":"1分钟","aside":false,"hash":1053130082}},{"url":"56","text":"\\n\\n走累了、垂下头，忽然发现阳光从背后照来，便不由得顾影自怜起来。","frontmatter":{"title":"五六","date":"2020-12-10T08:44:54.000Z","length":"27字","time":"1分钟","aside":false,"hash":772314378}},{"url":"55","text":"\\n\\n学量子力学的时候，由于没有任何直觉可凭借，我把思想完全交给数学改造，并由此建立新的直觉；然而在学相对论的时候，由于一般与特殊的联系性，侥幸抱着特殊直觉揣摩一般规律，反而阻碍了新直觉的建立。\\n\\n这大概就是所谓不懂装懂，不如不懂。","frontmatter":{"title":"五五","date":"2020-11-26T20:48:36.000Z","length":"101字","time":"1分钟","aside":false,"hash":1954379908}},{"url":"54","text":"\\n\\n英语课上考美国政治，其中一题是：美国是政教分离的国家吗？法国人都认为不是，因为总统上任向圣经宣誓。\\n\\n于是老师辩解到，其实他们可以向任何书宣誓，比如穆斯林可以向古兰经宣誓。哦，任何书？正当我想发话时，老师加了一句：但比起无神论者，美国民众可能宁愿接受一个同性恋或者穆斯林。","frontmatter":{"title":"五四","date":"2020-11-24T14:45:12.000Z","length":"120字","time":"1分钟","aside":false,"hash":1015103053}},{"url":"53","text":"\\n\\n也许某一天，现实瓦解了。你从梦中醒来，才发现你不是昨天睡下的，而是自出生以来的沉眠。——黑客帝国","frontmatter":{"title":"五三","date":"2020-11-22T13:58:24.000Z","length":"41字","time":"1分钟","aside":false,"hash":279683028}},{"url":"52","text":"\\n\\n今天 hss 的考题是，群众会威胁到个人吗？为了八股，我提了一句，为什么是群众威胁个人而不是个人威胁群众呢？这说明题目本身倾向于前者的可能性，即多数裹挟少数。\\n\\n现在转念一想，少数裹挟多数的事情也并不罕见。只是事情完了，责任就被推给了既受苦又无辜的多数。我最终违心的写下了“西方政治正确”的对法西斯历史的唯心观点。事实上，法西斯极权统治下，被裹挟的恰恰是群众。苏联解体，不也是么？再引申些，不还是么？\\n\\n说到底，为少数辩护仿佛最能体现公义；多数天生被认为是强势的一方。但因为这种成见，即便当正义要求站在多数的一边时，也时常难得伸张。有些事情仿佛是多数人裹挟了少数人，仔细看却是少数人裹挟多数人。为一两个人伸张正义叫平反，为绝大多数人伸张正义叫革命。被裹挟的少数人有些平反了，被裹挟的多数人期待的革命却停滞了。平反不常有，革命更稀罕。\\n\\n唯心主义的弱点就在于它的禁区，即唯心的部分。因而学 hss 总觉得它想做点事，但做不成。永远都在真理的门口兜圈子。就像一头栽在豆腐上，却连豆腐都撞不动。","frontmatter":{"title":"五二","date":"2020-11-19T14:23:24.000Z","length":"388字","time":"2分钟","aside":false,"hash":-716004213}},{"url":"51","text":"\\n\\n今天看到郑强教授说的一句话：\\n\\n当一个人追求生活必需品的时候，他是勤劳而勇敢的\\n\\n当一个人开始追求消费品的时候，他变得懒惰而温和\\n\\n当一个人开始追求奢侈品的时候，他变得软弱而乖戾\\n\\n慨然有感：\\n\\n人心不是天生善或恶的，但善与恶天生是人心的。\\n\\n悲天悯人并非根植于对他人的怜悯或憎恶，而源于他们的自省与自知。人若有心自助，何不倾力相助？若此，虽朽木犹可雕也。人虽不知，亦不愠矣；箪食瓢饮，亦无忧矣。鞠躬尽瘁，亦无怨矣；死而后已，亦无悔矣。没于后世，亦不疾矣。盖棺论定，亦无惧矣。千秋功过，自与评说。","frontmatter":{"title":"五一","date":"2020-11-11T23:57:43.000Z","length":"209字","time":"1分钟","aside":false,"hash":-495897557}},{"url":"50","text":"\\n\\n绝不能在吃第一口的时候决定放多少辣","frontmatter":{"title":"五〇","date":"2020-10-31T17:07:40.000Z","length":"17字","time":"1分钟","aside":false,"hash":-110468341}},{"url":"49","text":"\\n\\n人各有心。通人之心，我之心也。","frontmatter":{"title":"四九","date":"2020-10-23T00:10:09.000Z","length":"12字","time":"1分钟","aside":false,"hash":1798100204}},{"url":"48","text":"\\n\\n鸽得不鸽得？鸽得、鸽得尔。","frontmatter":{"title":"四八","date":"2020-10-19T15:19:08.000Z","length":"10字","time":"1分钟","aside":false,"hash":1011551091}},{"url":"47","text":"\\n\\n君子无罪，怀璧其罪","frontmatter":{"title":"四七","date":"2020-10-14T21:36:12.000Z","length":"8字","time":"1分钟","aside":false,"hash":-428389282}},{"url":"46","text":"\\n\\n学习大概就是开始我觉得书本在胡说八道，结束我觉得自己在胡思乱想","frontmatter":{"title":"四六","date":"2020-09-24T00:13:19.000Z","length":"30字","time":"1分钟","aside":false,"hash":1792057970}},{"url":"45","text":"\\n\\n今天又旁听了一场英语辩论，主题是美国大学的招生制度是不是 broken？正方一个土耳其人，反方一个黎巴嫩人，嘉宾一个印度人。辩论主要围绕公平和效率展开，散会后还闲聊到加拿大身份政治深化改革区。就在我的马克思主义即将脱口而出时，天降暴雨，大家各回各家了。","frontmatter":{"title":"四五","date":"2020-09-23T19:21:51.000Z","length":"110字","time":"1分钟","aside":false,"hash":1931793395}},{"url":"44","text":"\\n\\n无意间翻到了学堂毕业生网站，看到了赵老师。整个页面只有他的照片是空白，很是刺眼。他的头衔也并非教授，只是个普通的讲师（这很文史哲）。尽管如此他对我的影响并不亚于数学老师。学数学非常耗费心力，此心力之恢复，正在赵老师的课堂上最为旺盛。因而他的课是我枯燥日子里翘首相盼的。我也永远不会忘记他那日在黑板上不知是巧合还是冥冥中的必然写下的润和心。在此之前，我心中确有这个理想的躯壳，但正是那一瞬，他把他的音容笑貌注进了这个理想，他让我意识到一颗近在咫尺的真心，富有激情活力。这个理想，终于不再是文章和细语，历史和风景，他它等来了另一颗此在此间的心，听它澎湃的跳动，一切都生机勃发起来，心中的郁结也冲荡一尽。此后虽也听过一些网络公开课，无论是山大的史记还是武大的说文亦或复旦的烟王，感情终不至此。如今又退回上网课，愈是感慨万分。\\n\\n没看红楼梦以前，对它有公认的偏见，认为宝玉不过是个花花公子罢了。他总是发脾气，动不动就赌咒毒誓，还经常伤春悲秋泪流满面。殊不知他只想要一颗真心。谁都想要一颗真心，只是曹雪芹看穿了他无奈的幼稚戏。\\n\\n这世界不乏真心，古书里到处是它的痕迹，但是活着跳动的真心，试问又能寻着几颗呢？\\n\\n于是人们要么背叛了真心，要么沦为公认的幼稚病。真正找到的，是不是又秘而不宣，暗自窃喜呢？嗯这是羡慕，这是嫉妒，这是庸人妄加揣度 🥱。","frontmatter":{"title":"四四","date":"2020-09-21T20:43:24.000Z","length":"506字","time":"2分钟","aside":false,"hash":218993912}},{"url":"43","text":"\\n\\n咏法兰西\\n\\n首轮抗疫挽回法兰西的尊严\\n\\n二次高峰教它悉数缴还\\n\\n任性的公民尽情狂欢\\n\\n孱弱的政府正为它的暧昧买单\\n\\n病毒会避开熟人传染\\n\\n口罩只让我呼吸困难\\n\\n旧王已死\\n\\n为吾皇加冕新冠！","frontmatter":{"title":"四三","date":"2020-09-16T08:00:31.000Z","length":"77字","time":"1分钟","aside":false,"hash":59436098}},{"url":"42","text":"\\n\\n周围的病例越来越多了\\n\\n珍惜不上网课的日子...","frontmatter":{"title":"四二","date":"2020-09-15T23:13:15.000Z","length":"19字","time":"1分钟","aside":false,"hash":-1803660481}},{"url":"41","text":"\\n\\n仗着四级英语和一个土耳其人一个印度人和一个美国人聊了一个多小时，说到 quora 上人均 MIT 毕业生，笑死我了\\n\\n果然天下乌鸦一般黑","frontmatter":{"title":"四一","date":"2020-09-14T19:38:06.000Z","length":"54字","time":"1分钟","aside":false,"hash":881158704}},{"url":"40","text":"\\n\\n麻油灯，亮又明，芝麻油烩些价白菜心。\\n\\n红豆角角双抽筋，呼儿嗨吆，谁也不能卖良心。\\n\\n苦曲儿啊","frontmatter":{"title":"四〇","date":"2020-09-14T00:06:34.000Z","length":"37字","time":"1分钟","aside":false,"hash":905698509}},{"url":"39","text":"\\n\\n抗疫不就是奥运会扩大化么，反映人心国力啊","frontmatter":{"title":"三九","date":"2020-09-10T10:17:11.000Z","length":"19字","time":"1分钟","aside":false,"hash":949817142}},{"url":"38","text":"\\n\\n老三国的台词就像古小说，新三国的台词就像网文。。。","frontmatter":{"title":"三八","date":"2020-09-05T23:08:11.000Z","length":"21字","time":"1分钟","aside":false,"hash":1034546330}},{"url":"37","text":"\\n\\n歌单里的法语歌，多数是外国人写的 bossa nova 和爵士。本土的流行歌我到现在还不感冒。平时这帮人大晚上开趴到 bgm 单纯是崩崩崩。军训的时候听的法国军歌也毫无气势，旋律和歌词都在倾诉苦难，不见乐观积极奋斗，只有革命时期的歌曲风骨犹存。我常说法国乃冢中枯骨，一部分是它的音乐造成我这样的想法，过去那个法兰西，现在只存在于精法的梦中。那天去街上买东西，路过一个足球场，于是我又发出新的祝福：愿黑人音乐拯救法兰西。","frontmatter":{"title":"三七","date":"2020-09-01T15:23:08.000Z","length":"179字","time":"1分钟","aside":false,"hash":-1104755803}},{"url":"36","text":"\\n\\n法国政府机关要是能拿出电信公司十分之一的赚钱积极性我都谢天谢地了。这很资本主义。","frontmatter":{"title":"三六","date":"2020-09-01T12:42:29.000Z","length":"38字","time":"1分钟","aside":false,"hash":883285746}},{"url":"35","text":"\\n\\n九月还没到，已经有点萧瑟了。好冷啊（抖）","frontmatter":{"title":"三五","date":"2020-08-30T23:15:14.000Z","length":"16字","time":"1分钟","aside":false,"hash":1439752326}},{"url":"34","text":"\\n\\n本想往菠菜汤里加点淡菜提鲜的，没想到放的时机不对菠菜煮败了\\n\\n但也意外发现法式奶酪焗菠菜的黑暗原理\\n\\n完美","frontmatter":{"title":"三四","date":"2020-08-29T19:11:42.000Z","length":"48字","time":"1分钟","aside":false,"hash":-1766136857}},{"url":"33","text":"\\n\\n旅法有感\\n\\n世事多诡谲，凡夫怎堪度？\\n\\n广交朋共友，坐待命与运。","frontmatter":{"title":"三三","date":"2020-08-18T11:17:16.000Z","length":"24字","time":"1分钟","aside":false,"hash":792795657}},{"url":"32","text":"\\n\\n机密文档：浙江高考满分作文\\n\\n密码：后现代西哲\\n\\n密码正确，恭喜上树！\\n\\n哲学名词党比数学同侪厉害多了，不仅吓坏同学，还能吓坏老师。这篇文章不禁又让我想起某些国风歌词和英文科技写作。评分给学生指了一条邪路，也暴露了老师的浅陋。\\n\\n故作高深也是一种中二病呐，应该早早治愈为妙。","frontmatter":{"title":"三二","date":"2020-08-03T09:57:23.000Z","length":"117字","time":"1分钟","aside":false,"hash":1543769190}},{"url":"31","text":"\\n\\n你害怕里头钻出个怪物\\n\\n我害怕外头陌生的温度","frontmatter":{"title":"三一","date":"2020-07-21T01:16:59.000Z","length":"20字","time":"1分钟","aside":false,"hash":-904170105}},{"url":"30","text":"\\n\\n鼎：食器-权力\\n\\n伊尹：厨子-政治家\\n\\n中国不愧是吃货国","frontmatter":{"title":"三〇","date":"2020-07-20T00:41:30.000Z","length":"20字","time":"1分钟","aside":false,"hash":885785038}},{"url":"29","text":"\\n\\n大多数人都在期盼凭空出现一个英雄，却没有勇气发挥积蓄的潜能，成为那样一个人。","frontmatter":{"title":"二九","date":"2020-07-13T14:19:18.000Z","length":"35字","time":"1分钟","aside":false,"hash":-2089697652}},{"url":"28","text":"\\n\\n逼死英雄汉，处处是梁山","frontmatter":{"title":"二八","date":"2020-07-13T13:09:53.000Z","length":"10字","time":"1分钟","aside":false,"hash":896713856}},{"url":"27","text":"\\n\\n历史是信仰，生活是修行","frontmatter":{"title":"二七","date":"2020-07-10T15:32:16.000Z","length":"10字","time":"1分钟","aside":false,"hash":34234541}},{"url":"26","text":"\\n\\n凑合到普通，封城至今晚餐。每天最快乐，做晚饭。从不看菜谱，全凭臆想。几乎是杂烩，毕竟一个盘儿。","frontmatter":{"title":"二六","date":"2020-07-02T08:25:07.000Z","length":"39字","time":"1分钟","aside":false,"hash":-1967746261}},{"url":"25","text":"\\n\\n活到老 学到老\\n\\n九十九 莫白头","frontmatter":{"title":"二五","date":"2020-06-30T23:43:37.000Z","length":"12字","time":"1分钟","aside":false,"hash":-1591485118}},{"url":"24","text":"\\n\\n现实够复杂了，某些理论家还添油加醋","frontmatter":{"title":"二四","date":"2020-06-30T21:28:49.000Z","length":"16字","time":"1分钟","aside":false,"hash":-1807888084}},{"url":"23","text":"\\n\\n躺在床上的大文豪一提起笔就原形毕露了","frontmatter":{"title":"二三","date":"2020-06-23T07:06:49.000Z","length":"18字","time":"1分钟","aside":false,"hash":-1984960192}},{"url":"22","text":"\\n\\n闲来无事翻了翻诸位的说说\\n\\n有的人热情奔放\\n\\n有的人冷静节制\\n\\n都是生活啊","frontmatter":{"title":"二二","date":"2020-06-19T00:02:18.000Z","length":"31字","time":"1分钟","aside":false,"hash":244704993}},{"url":"21","text":"\\n\\n终于有空理发了\\n\\n剪了烦恼丝的感觉真好\\n\\n然而没有烦恼丝也是一种烦恼呢","frontmatter":{"title":"二一","date":"2020-06-18T23:37:11.000Z","length":"31字","time":"1分钟","aside":false,"hash":418849089}},{"url":"20","text":"\\n\\n洗脑：对前提的怀疑被千万条可靠的结论淹没，达到臀脑分离的境界","frontmatter":{"title":"二〇","date":"2020-06-09T07:57:49.000Z","length":"28字","time":"1分钟","aside":false,"hash":-1854244342}},{"url":"19","text":"\\n\\n在网上兜兜转转终于破案了\\n\\n谁能想到一个做分子生物学的博士后课外自学汉语音韵学构拟了中古汉语拼音现在在中央民族大学搞社会学和人类学研究呢？\\n\\n人的全面发展果然永无止境，任重而道远！","frontmatter":{"title":"一九","date":"2020-05-22T00:36:22.000Z","length":"83字","time":"1分钟","aside":false,"hash":432390471}},{"url":"18","text":"\\n\\n这几天突然涌出好多事来，难以释怀\\n\\n善与恶、公与私、佛与魔、良心与尘心、本体和异化物的永恒周旋\\n\\n生命的轮回、历史的轮回\\n\\n凡超脱轮回的即是不朽，佛是不朽，他是不朽\\n\\n人生有两个瞬间能洞见这不朽，生的一刻、死的一刻，凡此之间皆入尘网\\n\\n前一个瞬间你不必了悟，后一个瞬间你枉自了悟\\n\\n自渡与普渡，小乘佛教、大乘佛教\\n\\n尘世是真正的洗礼，和光同尘，光的一面、尘的一面\\n\\n他释怀了，他实现了他的夙愿，他没有向世界妥协。他也没有拷问我们，是我们扪心自问。昔人已逝，逝者是不会被抹黑的，被抹黑的是它的衣钵。我们继承他的衣钵，我们就要背负。\\n\\n一个人能够反叛本性，却不能反叛他的阶级\\n\\n一个人能够拯救自己，却不能拯救他的阶级\\n\\n无产阶级只有解放全人类才能解放自己\\n\\n无穷的悖论只能用悖论的无穷解答，这是解答，还是无穷的诘问？\\n\\n个人本不存在，他只是同一颗人心的化身，历史是它的记忆，关于昨天的，如他婴儿时一样模糊的记忆。历史是它的生活，它的见证。\\n\\n而我将是它的见证。","frontmatter":{"title":"一八","date":"2020-05-15T01:26:27.000Z","length":"360字","time":"2分钟","aside":false,"hash":1289318026}},{"url":"17","text":"\\n\\n在新的国难中默哀过去","frontmatter":{"title":"一七","date":"2020-05-12T00:54:29.000Z","length":"10字","time":"1分钟","aside":false,"hash":-1388688202}},{"url":"16","text":"\\n\\n亡羊补牢，补上了就不晚，没补上就已晚。。\\n\\n哎！希望自己能补上！","frontmatter":{"title":"一六","date":"2020-04-26T23:06:58.000Z","length":"24字","time":"1分钟","aside":false,"hash":-1623162514}},{"url":"15","text":"\\n\\n我看各种新闻甚至连外交部发言人都说出“污名化”这种狗屁不通的词了\\n\\n难道你们都忘了”侮辱”“污蔑”“抹黑”了么？\\n\\n这可笑性也太强了！","frontmatter":{"title":"一五","date":"2020-04-21T23:11:15.000Z","length":"53字","time":"1分钟","aside":false,"hash":-550517414}},{"url":"14","text":"\\n\\n初中每逢大考，宣传委员照例要在黑板上写艺术字。这以往都是一些“认真仔细”的话，并不新奇，顶多用个成语。偏这次院长很是振奋，在黑板上写下“燃烧吧，小宇宙！”几个叛逆的字来，引起一阵骚动。院长拍拍笔灰，志得意满地走下讲台。结果隔壁班的小未走过来，说这标语不伦不类，就给换掉了。那时大家都知道这是日漫的台词，被擦也无可厚非。\\n\\n直到今天听王老师讲心学，讲到日本人对心学的推崇，弹幕里突然冒出一句“燃烧吧，小宇宙”，我才突然明白此话正是取自“吾心即是宇宙”。可是那天晚上，没人识出阳明。一群中二少年引这中二的话，原也自然。却不知那位同为惑者的“天姥游子”，如今得以放心了吗","frontmatter":{"title":"一四","date":"2020-04-21T14:09:46.000Z","length":"243字","time":"1分钟","aside":false,"hash":-1621817601}},{"url":"13","text":"\\n\\n千里搭凉棚，天下没有不散的筵席\\n\\nEvery culture have the similar proverb, except the Dane has an exception of bad humour.","frontmatter":{"title":"一三","date":"2020-04-15T07:40:05.000Z","length":"29字","time":"1分钟","aside":false,"hash":923561136}},{"url":"12","text":"\\n\\n搜索脑里\\n\\n未完的龃龉\\n\\n对着空气\\n\\n还击着你的问题\\n\\n经常做这种蠢事诶…","frontmatter":{"title":"一二","date":"2020-04-09T22:47:47.000Z","length":"28字","time":"1分钟","aside":false,"hash":-1668307727}},{"url":"11","text":"\\n\\n绘事不难于写形，而难于得意。得其意而点出之，则万物之理，挽于尺素间矣，不甚难哉","frontmatter":{"title":"一一","date":"2020-03-30T19:15:47.000Z","length":"34字","time":"1分钟","aside":false,"hash":-1643839847}},{"url":"10","text":"\\n\\n人学习最快的时候莫过于情形所迫","frontmatter":{"title":"一〇","date":"2020-03-26T09:27:53.000Z","length":"15字","time":"1分钟","aside":false,"hash":-148698936}},{"url":"9","text":"\\n\\n“我悲哀地发现根本就无法还原事实，记忆总是被我的情感改头换面，并随之捉弄我、背叛我，把我搞得头脑混乱，真伪难辨”","frontmatter":{"title":"九","date":"2020-03-12T07:37:27.000Z","length":"49字","time":"1分钟","aside":false,"hash":-1189915914}},{"url":"8","text":"\\n\\n我现在深切的觉得马克思主义信仰并不是学好马原毛概党课就能获得的，没有哪一种坚定的世界观是可以通过灌输获得的（如果有就是通常说的洗脑吧）作为一种世界观，他是通过实践和体验养成的。实践和体验什么？反映马克思主义原理的材料在哪儿？便是历史。而历史材料不能完整地包含于教材之中，对他的学习也无法局限于教科书。进一步的，马克思主义是理性总结的科学，却不能单凭理性就能学到，因为他的根基，那些唯物史的材料，是需要有一颗悲悯恻隐是非善恶之心才能读懂的，这是读一切史书的前提，是超出理性直指心底的切身体验，是古今共鸣的体验。文字传达的身临其境的体验是文字的创举，也是史书的意义。因而马克思主义原理的确有哲学的门槛，特别是西方哲学思辨的门槛，可他的源泉是朴素的，是雅俗共赏的，是存在于每颗良心之中的，正如辩证法早就存在于中国人的心灵世界中。所以学马克思，远不是把联系矛盾否定之否定倒背如流就能学到的（那样最多只能学到黑格尔）。这样对某些人来说，学马克思的门槛的确提高了，因为他不是坚持应试教育基本精神就能学到的，但反过来对绝大多数脚踏实地的人来说，马克思主义变得更加亲切友善了（这也正所谓马克思的哲学是劳苦大众的哲学）因而马克思主义是可以中国化的，关键在于怎么让他说中国话讲中国故事，并且在教学中淡化他的意识形态功能，而让中国学生认识到这种外来哲学的隔阂从历史材料渊源来说，是不存在的。毕竟理性只能说服人们相信推理，而那个大前提，那个公理，则是需要通过读史激发的感情来信仰。","frontmatter":{"title":"八","date":"2020-02-29T11:46:57.000Z","length":"582字","time":"2分钟","aside":false,"hash":495423591}},{"url":"7","text":"\\n\\n新中国和旧中国的区别不是天安门，而是人民英雄纪念碑","frontmatter":{"title":"七","date":"2020-02-13T17:19:10.000Z","length":"24字","time":"1分钟","aside":false,"hash":1534865023}},{"url":"6","text":"\\n\\n夫生也有涯而心也无涯，以有涯负无涯犹不能胜，况随无涯之知乎？","frontmatter":{"title":"六","date":"2020-02-04T22:39:38.000Z","length":"27字","time":"1分钟","aside":false,"hash":262333614}},{"url":"5","text":"\\n\\n“资本不是慈善家，但慈善是资本家”","frontmatter":{"title":"五","date":"2020-01-31T23:31:17.000Z","length":"14字","time":"1分钟","aside":false,"hash":-1503236278}},{"url":"4","text":"\\n\\n有话就说 有话就写\\n\\n而且要彻底\\n\\n因为每次彻底之后\\n\\n才会出现美妙的空虚\\n\\n—— 蓝色骨头","frontmatter":{"title":"四","date":"2020-01-18T21:36:32.000Z","length":"34字","time":"1分钟","aside":false,"hash":-1570216628}},{"url":"3","text":"\\n\\n理性不是太阳\\n\\n太阳懂得落山","frontmatter":{"title":"三","date":"2020-01-16T22:54:20.000Z","length":"12字","time":"1分钟","aside":false,"hash":-1217204696}},{"url":"2","text":"\\n\\n精心呵护用了才一年多点的电脑固态盘坏了\\n\\n时时勤拂拭与本来无一物的境界高下立判","frontmatter":{"title":"二","date":"2020-01-13T23:00:21.000Z","length":"37字","time":"1分钟","aside":false,"hash":-566978764}},{"url":"1","text":"\\n\\n当伟大的革命家在世时，压迫阶级总是不断迫害他们，以最恶毒的敌意、最疯狂的仇恨、最放肆的造谣和诽谤对待他们的学说。在他们逝世以后，便企图把他们变为无害的神像，可以说是把他们偶像化，赋予他们的名字某种荣誉，以便‘安慰’和愚弄被压迫阶级，同时却阉割革命学说的内容，磨灭它的革命锋芒，把它庸俗化。——列宁《国家与革命》\\n","frontmatter":{"title":"一","date":"2019-12-31T17:01:09.000Z","length":"136字","time":"1分钟","aside":false,"hash":611811246}}]`),u={key:0},g={key:1,class:"text-center"},b=JSON.parse('{"title":"随想","description":"","frontmatter":{"layout":"index","title":"随想","lastUpdated":false,"aside":false,"outline":false},"headers":[],"relativePath":"idea/index.md","filePath":"idea/index.md"}'),x={name:"idea/index.md"},v=Object.assign(x,{setup(T){return(Z,c)=>{const h=i("IndexItem"),d=i("IndexWrapper");return t(),e("div",null,[a(d,null,{title:l(()=>[m("随想")]),posts:l(()=>[s(r).length!==0?(t(),e("div",u,[(t(!0),e(f,null,o(s(r),(n,p)=>(t(),e("div",null,[a(h,{url:n.url,title:n.frontmatter.title,date:n.frontmatter.date,text:n.text},null,8,["url","title","date","text"])]))),256))])):(t(),e("div",g," 空空如也~ "))]),_:1})])}}});export{b as __pageData,v as default};
